import type { Macete } from './types'

export const MACETES: Macete[] = [
  {num:1,disc:`Ética`,title:`Exceção aos Atos Privativos`,kw:`HC = QUALQUER PESSOA`,exp:`A impetração de habeas corpus não é atividade privativa de advogado, podendo ser realizada por qualquer pessoa (Art. 1º, § 1º, EOAB).`,ex:`Familiar do preso impetra HC diretamente, sem advogado: ato válido.`,peg:`A FGV apresenta o HC como ato privativo de advogado. Errado! É o único ato que qualquer pessoa pode praticar.`},
  {num:2,disc:`Ética`,title:`Atos Nulos`,kw:`SEM OAB = NULO`,exp:`Atos privativos de advocacia praticados por pessoas não inscritas na OAB, ou por advogados suspensos, impedidos, licenciados ou que exerçam atividade incompatível, são nulos de pleno direito (Art. 4º e Parágrafo único, EOAB).`,ex:`Pessoa sem inscrição assina petição: ato nulo, sem efeito.`,peg:`Confundir nulidade com anulabilidade. Aqui é NULO (absoluto), não anulável.`},
  {num:3,disc:`Ética`,title:`Inexistência de Hierarquia`,kw:`SEM HIERARQUIA`,exp:`Não há hierarquia entre advogados, juízes e promotores. Durante as audiências, os advogados devem permanecer no mesmo plano topográfico e em posição equidistante em relação ao magistrado (Art. 6º, EOAB).`,ex:`Advogado não se levanta ao chefe do MP entrar: conduta correta.`,peg:`Pensar que magistrado é superior ao advogado na audiência.`},
  {num:4,disc:`Ética`,title:`Quebra da Inviolabilidade (Escritório)`,kw:`4 REQUISITOS CUMULATIVOS`,exp:`A inviolabilidade do escritório não é absoluta. Para ser quebrada, exige-se decisão judicial motivada, indícios de autoria/materialidade de crime, mandado específico pormenorizado e a presença obrigatória de um representante da OAB (Art. 7º, § 6º, EOAB).`,ex:`Busca sem representante da OAB: ilegal.`,peg:`Achar que basta mandado judicial.`},
  {num:5,disc:`Ética`,title:`Acesso aos Autos (Sigilo)`,kw:`SIGILO = PROCURAÇÃO OBRIGATÓRIA`,exp:`O advogado tem o direito de examinar autos de qualquer processo (mesmo sem procuração e em andamento). Contudo, se o processo estiver sob sigilo, a apresentação da procuração torna-se obrigatória (Art. 7º, XIII, XIV e § 10, EOAB).`,ex:`Processo sigiloso: advogado sem procuração não tem acesso.`,peg:`Pensar que sempre precisa de procuração. A regra é que não precisa, exceto no sigilo.`},
  {num:6,disc:`Ética`,title:`Prisão Cautelar do Advogado`,kw:`SALA DE ESTADO MAIOR`,exp:`O advogado não pode ser preso antes do trânsito em julgado, a não ser em Sala de Estado Maior. Caso não haja essa sala, a prisão deve ser convertida em prisão domiciliar (Art. 7º, V, EOAB).`,ex:`Não há Sala de Estado Maior: prisão cautelar convertida em domiciliar.`,peg:`Achar que advogado pode ser preso normalmente.`},
  {num:7,disc:`Ética`,title:`Direitos da Advogada Mãe`,kw:`30 DIAS + ÚNICA PATRONA`,exp:`A advogada que der à luz ou adotar tem direito à suspensão dos prazos processuais por 30 dias, desde que seja a única patrona da causa e notifique o cliente por escrito (Art. 7º-A, EOAB).`,ex:`Advogada que não é única patrona dá à luz: não há suspensão automática.`,peg:`Esquecer o requisito "única patrona" e a notificação por escrito.`},
  {num:8,disc:`Ética`,title:`Inscrição do Estagiário`,kw:`SEM EXAME DE ORDEM`,exp:`Diferente do advogado, o estagiário não precisa de diploma ou aprovação no Exame de Ordem para se inscrever na OAB. Ele precisa ter sido admitido em estágio profissional de advocacia e estar nos últimos anos do curso de Direito (Art. 9º, EOAB).`,ex:`Aluno do 4º ano admitido em escritório: pode se inscrever como estagiário.`,peg:`Confundir requisitos do advogado com os do estagiário.`},
  {num:9,disc:`Ética`,title:`Inscrição Suplementar (Regra das 5 Causas)`,kw:`MAIS DE 5 = SUPLEMENTAR`,exp:`O advogado que patrocinar mais de 5 causas por ano (habitualidade) em outro Estado (unidade federativa) é obrigado a requerer inscrição suplementar no respectivo Conselho Seccional (Art. 10, § 2º, EOAB).`,ex:`Advogado de SP com 6 causas no RJ/ano: obrigado a pedir inscrição suplementar.`,peg:`Achar que pode advogar em qualquer estado sem restrição.`},
  {num:10,disc:`Ética`,title:`Licenciamento x Cancelamento`,kw:`CANCEL=DEFINITIVO / LIC=TEMPORÁRIO`,exp:`O cancelamento é definitivo e o advogado perde o número da OAB (ex: falecimento, atividade incompatível definitiva). O licenciamento é temporário e o profissional mantém o número ao fim da licença (ex: pedido justificado, doença mental curável) (Art. 11 e 12, EOAB).`,ex:`Advogado com doença mental curável: licenciamento, não cancelamento.`,peg:`Trocar os institutos. Cancelamento é permanente; licenciamento é temporário.`},
  {num:11,disc:`Ética`,title:`Unicidade Societária na mesma Seccional`,kw:`1 SOCIEDADE POR SECCIONAL`,exp:`Um advogado não pode integrar mais de uma sociedade de advogados, nem ser titular de mais de uma sociedade unipessoal, nem misturar ambas, dentro da mesma área territorial do respectivo Conselho Seccional (Art. 15, § 4º, EOAB).`,ex:`Advogado sócio de duas sociedades na mesma seccional: vedado.`,peg:`Pensar que pode participar de várias sociedades na mesma seccional.`},
  {num:12,disc:`Ética`,title:`Razão Social (Proibição de Nome Fantasia)`,kw:`NOME REAL OBRIGATÓRIO`,exp:`A razão social da sociedade deve obrigatoriamente conter o nome de pelo menos um advogado responsável. É expressamente proibido o uso de nome fantasia ou características de sociedade empresária (LTDA, S/A) (Art. 16 e § 1º, EOAB).`,ex:`"Silva & Associados Advocacia Ltda": inválido.`,peg:`Usar denominações empresariais como S/A ou Ltda.`},
  {num:13,disc:`Ética`,title:`Honorários e Acordo Extrajudicial`,kw:`ACORDO SEM ADVOGADO = HONORÁRIOS`,exp:`Se o cliente fizer um acordo com a parte contrária sem o conhecimento ou anuência do seu advogado, esse acordo não prejudica o direito do advogado de receber seus honorários convencionados e os de sucumbência (Art. 24, § 4º, EOAB).`,ex:`Cliente fecha acordo sem avisar o advogado: advogado ainda recebe honorários.`,peg:`Pensar que o acordo do cliente libera os honorários.`},
  {num:14,disc:`Ética`,title:`Liberação de Bens Bloqueados`,kw:`20% DESBLOQUEIO`,exp:`Caso o cliente sofra bloqueio universal de patrimônio, o advogado pode requerer o desbloqueio de até 20% dos bens para o pagamento de honorários. Essa regra não se aplica a crimes de tráfico de drogas ou exploração de trabalho escravo (Art. 24-A, EOAB).`,ex:`Cliente com bloqueio total por crime comum: advogado pede 20% para honorários.`,peg:`Aplicar a regra a crimes de tráfico de drogas ou trabalho escravo.`},
  {num:15,disc:`Ética`,title:`Substabelecimento com Reserva de Poderes`,kw:`COM RESERVA = SEM COBRANÇA DIRETA`,exp:`O advogado que recebe um substabelecimento com reserva não pode cobrar honorários diretamente do cliente sem a intervenção do advogado original que o substabeleceu (Art. 26, EOAB).`,ex:`Advogado B recebeu substabelecimento com reserva: cobra pelo advogado A.`,peg:`Achar que o substabelecido com reserva pode cobrar direto do cliente.`},
  {num:16,disc:`Ética`,title:`Incompatibilidade x Impedimento`,kw:`INCOMPAT=TOTAL / IMPED=PARCIAL`,exp:`A Incompatibilidade gera proibição total para o exercício da advocacia (mesmo em causa própria). O Impedimento é uma proibição parcial, ou seja, o advogado pode atuar, exceto em certas situações específicas (Art. 27 a 30, EOAB).`,ex:`Servidor em cargo incompatível: não pode advogar nem em causa própria.`,peg:`Confundir incompatibilidade com impedimento.`},
  {num:17,disc:`Ética`,title:`Incompatibilidade e Militares/Policiais (Decisão STF)`,kw:`MILITAR/POLICIAL = INCOMPATÍVEL`,exp:`Militares da ativa e ocupantes de cargos vinculados à atividade policial são incompatíveis com a advocacia. O STF (ADI 7227) declarou inconstitucional a possibilidade de advogarem em causa própria (Art. 28, V, VI e §§ 3º e 4º, EOAB).`,ex:`Delegado em atividade quer advogar em causa própria: vedado.`,peg:`Pensar que militares/policiais podem advogar em causa própria.`},
  {num:18,disc:`Ética`,title:`Impedimento (O Macete do Professor)`,kw:`PROFESSOR = PODE ADVOGAR CONTRA`,exp:`Servidores públicos não podem advogar contra a Fazenda Pública que os remunera. A exceção de ouro cai sempre: docentes (professores) de cursos jurídicos não sofrem esse impedimento, podendo advogar contra a entidade que os remunera (Art. 30, Parágrafo único, EOAB).`,ex:`Professor universitário pode advogar contra a universidade pública que o remunera.`,peg:`Aplicar o impedimento ao professor de curso jurídico. Ele é a exceção expressa na lei.`},
  {num:19,disc:`Ética`,title:`Renúncia ao Mandato (Os 10 dias)`,kw:`RENÚNCIA = 10 DIAS`,exp:`Se o advogado renunciar, deve continuar representando o cliente por 10 dias após a notificação, salvo se um substituto assumir antes, para evitar o desamparo (Art. 5º, § 3º, EOAB e Art. 16, CED).`,ex:`Advogado notifica cliente da renúncia: continua por 10 dias.`,peg:`Achar que a renúncia é imediata.`},
  {num:20,disc:`Ética`,title:`Revogação do Mandato`,kw:`REVOGAÇÃO = IMEDIATA + HONORÁRIOS`,exp:`A revogação parte do cliente e cessa a atuação do advogado imediatamente. Apesar disso, o cliente não fica desobrigado de pagar os honorários proporcionais ao trabalho realizado (Art. 17, CED).`,ex:`Cliente revoga mandato no meio do processo: paga honorários proporcionais.`,peg:`Achar que revogação e renúncia têm os mesmos efeitos.`},
  {num:21,disc:`Ética`,title:`Sigilo Profissional`,kw:`SIGILO = ORDEM PÚBLICA`,exp:`É de ordem pública e independe do pedido do cliente. Só pode ser quebrado em situações extremas de justa causa, como grave ameaça à vida, honra ou para a própria defesa do advogado (Art. 35 a 37, CED).`,ex:`Cliente pede ao advogado que revele informação: advogado NÃO pode revelar sem justa causa.`,peg:`Pensar que o cliente pode dispensar o advogado do sigilo.`},
  {num:22,disc:`Ética`,title:`Publicidade (Vedações Absolutas)`,kw:`SEM RÁDIO/TV/OUTDOOR`,exp:`A publicidade deve ser sempre informativa. É expressamente vedada a utilização de rádio, cinema, televisão, outdoors, panfletos com intuito de captação e fotos pessoais ou de terceiros em cartões de visita (Art. 39, 40 e 44, § 2º, CED).`,ex:`Advogado anuncia no rádio: vedado.`,peg:`Pensar que qualquer publicidade é permitida.`},
  {num:23,disc:`Ética`,title:`Sanção de Exclusão`,kw:`EXCLUSÃO = 2/3 DO SECCIONAL`,exp:`É a penalidade mais grave, cancelando a inscrição na OAB. Só é aplicada se houver aprovação de 2/3 (quórum qualificado) do Conselho Seccional, nos casos de falsa prova de inscrição, crime infamante ou três suspensões (Art. 35 do EAOAB).`,ex:`Advogado com três suspensões: pode ser excluído com quórum de 2/3.`,peg:`Esquecer o quórum qualificado de 2/3.`},
  {num:24,disc:`Ética`,title:`Subseções da OAB`,kw:`SUBSEÇÃO = SEM PERSONALIDADE`,exp:`Diferente do Conselho Federal, dos Conselhos Seccionais e das Caixas de Assistência dos Advogados (que possuem personalidade jurídica própria), as Subseções não possuem personalidade jurídica; são partes autônomas do Conselho Seccional (Art. 45 e 60, EOAB). CONSTITUCIONAL`,ex:`Subseção da OAB não pode celebrar contratos em nome próprio.`,peg:`Atribuir personalidade jurídica às subseções.`},
  {num:25,disc:`Constitucional`,title:`Poder Constituinte Originário (Macete do "3IA")`,kw:`INICIAL ILIMITADO INCONDICIONADO AUTÔNOM`,exp:`O Poder Constituinte Originário é responsável pela criação de uma Constituição nova e é caracterizado por ser Inicial, Ilimitado, Incondicionado e Autônomo. Ele não se submete a nenhuma regra de direito anterior ou limitações jurídicas para instituir uma nova ordem jurídica.`,ex:`A CF/88 foi criada pelo PCO, sem limitações jurídicas anteriores.`,peg:`Confundir PCO com PCD Reformador. O PCO não tem limites; o Derivado tem.`},
  {num:26,disc:`Constitucional`,title:`Poder Constituinte Derivado Decorrente (Princípio da Simetria)`,kw:`PRINCÍPIO DA SIMETRIA`,exp:`A competência dos estados-membros para elaborar suas próprias Constituições estaduais sofre uma forte limitação por causa do Princípio da Simetria. Isso significa que as normas estaduais não podem contrariar a Constituição Federal, devendo refletir os seus princípios fundamentais, como no caso da segurança pública.`,ex:`Isso significa que as normas estaduais não podem contrariar a Constituição Federal, devendo refletir os seus princípios fundamentais, como no caso da segurança pública.`,peg:`A competência dos estados-membros para elaborar suas próprias Constituições estaduais sofre uma forte limitação por causa do Princípio da Simetria.`},
  {num:27,disc:`Constitucional`,title:`Poder Constituinte Difuso (Mutação Constitucional)`,kw:`MUTAÇÃO CONSTITUCIONAL`,exp:`A Constituição pode mudar seu significado ao longo do tempo sem que haja alteração no seu texto literal formal. A chamada "mutação constitucional" reflete adaptações na interpretação e na jurisprudência, a exemplo do reconhecimento de direitos de grupos minoritários, desde que respeitados os limites da Constituição.`,ex:`A chamada "mutação constitucional" reflete adaptações na interpretação e na jurisprudência, a exemplo do reconhecimento de direitos de grupos minoritários, desde que respeitados os limites da Constituição.`,peg:`A Constituição pode mudar seu significado ao longo do tempo sem que haja alteração no seu texto literal formal.`},
  {num:28,disc:`Constitucional`,title:`Vedação ao Anonimato e Direito de Resposta`,kw:`VEDAÇÃO AO ANONIMATO E DIREITO`,exp:`A liberdade de expressão é amplamente assegurada, mas a Constituição proíbe expressamente o anonimato. É admitido o uso de pseudônimos na manifestação do pensamento, contanto que isso não impeça a responsabilização do autor por ofensas e garanta o direito de resposta, que deve ser proporcional ao agravo (danos materiais, morais e de imagem).`,ex:`É admitido o uso de pseudônimos na manifestação do pensamento, contanto que isso não impeça a responsabilização do autor por ofensas e garanta o direito de resposta, que deve ser proporcional ao agravo (danos materiais, morais e de imagem).`,peg:`A liberdade de expressão é amplamente assegurada, mas a Constituição proíbe expressamente o anonimato.`},
  {num:29,disc:`Constitucional`,title:`Biografias e o Inexistente Direito ao Esquecimento`,kw:`BIOGRAFIAS E O INEXISTENTE DIREITO`,exp:`Segundo a jurisprudência do Supremo Tribunal Federal (STF), não é exigida autorização prévia para a publicação de biografias, reforçando a proibição de censura. Além disso, o Brasil não adota o "direito ao esquecimento", sendo amplamente permitida a divulgação de fatos históricos.`,ex:`Além disso, o Brasil não adota o "direito ao esquecimento", sendo amplamente permitida a divulgação de fatos históricos.`,peg:`Segundo a jurisprudência do Supremo Tribunal Federal (STF), não é exigida autorização prévia para a publicação de biografias, reforçando a proibição de censura.`},
  {num:30,disc:`Constitucional`,title:`Vacinação`,kw:`VACINAÇÃO`,exp:`Obrigatória sim, Forçada não: A jurisprudência estabelece que o Estado não pode aplicar a vacinação à força nas pessoas. Porém, a vacinação pode ser considerada obrigatória, podendo gerar sanções e restrições de direitos em caso de recusa, como a perda do poder familiar para pais que se recusam a vacinar os filhos.`,ex:`Porém, a vacinação pode ser considerada obrigatória, podendo gerar sanções e restrições de direitos em caso de recusa, como a perda do poder familiar para pais que se recusam a vacinar os filhos.`,peg:`Obrigatória sim, Forçada não: A jurisprudência estabelece que o Estado não pode aplicar a vacinação à força nas pessoas.`},
  {num:31,disc:`Constitucional`,title:`Interceptação Telefônica vs. CPI (O limite de poder)`,kw:`O LIMITE DE PODER`,exp:`É muito comum na prova a pegadinha envolvendo CPIs: Comissão Parlamentar de Inquérito (CPI) pode quebrar sigilo bancário e de dados telefônicos (o registro de quem ligou para quem e o tempo de duração da ligação). No entanto, a CPI não pode quebrar o sigilo das comunicações telefônicas (interceptação da conversa); para isso, é obrigatória a ordem judicial para fins de investigação criminal ou processo penal.`,ex:`No entanto, a CPI não pode quebrar o sigilo das comunicações telefônicas (interceptação da conversa); para isso, é obrigatória a ordem judicial para fins de investigação criminal ou processo penal.`,peg:`É muito comum na prova a pegadinha envolvendo CPIs: Comissão Parlamentar de Inquérito (CPI) pode quebrar sigilo bancário e de dados telefônicos (o registro de quem ligou para quem e o tempo de duração da ligação).`},
  {num:32,disc:`Constitucional`,title:`Inviolabilidade Domiciliar (O horário do mandado)`,kw:`O HORÁRIO DO MANDADO`,exp:`O cumprimento de ordem judicial no domicílio é uma exceção à inviolabilidade e só pode ocorrer durante o dia. A definição para a execução desse mandado abrange o período das 6h às 18h, ou alternativamente, do nascer ao pôr do sol.`,ex:`A definição para a execução desse mandado abrange o período das 6h às 18h, ou alternativamente, do nascer ao pôr do sol.`,peg:`O cumprimento de ordem judicial no domicílio é uma exceção à inviolabilidade e só pode ocorrer durante o dia.`},
  {num:33,disc:`Constitucional`,title:`Legitimados do Controle Concentrado (A regra do 3x3x3)`,kw:`A REGRA DO 3X3X3`,exp:`Para ajuizar ações do controle concentrado no STF (ADI, ADC, ADO e ADPF), lembre-se de 3 grupos. Três pessoas (Presidente da República, Procurador-Geral da República e Governador); Três mesas (Câmara dos Deputados, Senado Federal, e Assembleias/Câmara Distrital); e Três entidades (Conselho Federal da OAB, partido político com representação no Congresso e Confederação sindical/entidade de classe nacional).`,ex:`Três pessoas (Presidente da República, Procurador-Geral da República e Governador); Três mesas (Câmara dos Deputados, Senado Federal, e Assembleias/Câmara Distrital); e Três entidades (Conselho Federal da OAB, partido político com representação no Co`,peg:`Para ajuizar ações do controle concentrado no STF (ADI, ADC, ADO e ADPF), lembre-se de 3 grupos.`},
  {num:34,disc:`Constitucional`,title:`Efeito Vinculante no Controle Concentrado`,kw:`EFEITO VINCULANTE NO CONTROLE CONCENTRAD`,exp:`As decisões nessas ações (ADI, ADPF etc.) possuem efeito vinculante sobre a administração pública (direta e indireta) e demais órgãos do Poder Judiciário. A grande ressalva é que não há vinculação do Poder Legislativo em sua função atípica de legislar, ou seja, o Congresso pode criar nova lei que aborde o tema.`,ex:`A grande ressalva é que não há vinculação do Poder Legislativo em sua função atípica de legislar, ou seja, o Congresso pode criar nova lei que aborde o tema.`,peg:`As decisões nessas ações (ADI, ADPF etc.`},
  {num:35,disc:`Constitucional`,title:`Cláusulas Pétreas (O Limite Material das PECs)`,kw:`FORMA FEDERAL / DIREITOS / PODERES / VOT`,exp:`Uma Emenda Constitucional pode ser julgada inconstitucional pelo STF se ferir as cláusulas pétreas do artigo 60, § 4º. Para memorizar, lembre-se do quarteto intocável que não pode ser abolido: a forma federativa de Estado, os direitos e garantias individuais, a separação dos poderes e o voto (que precisa ser direto, secreto, universal e periódico).`,ex:`PEC que extingue o voto direto: inconstitucional.`,peg:`Incluir a forma de governo (república) como cláusula pétrea. Só a forma de Estado é pétrea.`},
  {num:36,disc:`Constitucional`,title:`Competência da Câmara versus Senado (Impeachment)`,kw:`IMPEACHMENT`,exp:`Grave a divisão de funções nos processos de crime de responsabilidade (impeachment) do Presidente da República. A Câmara dos Deputados detém a competência privativa para autorizar a instauração do processo (Art. 51, CF), mas é o Senado Federal que possui a atribuição de efetivamente julgar o Presidente (Art. 52, CF).`,ex:`51, CF), mas é o Senado Federal que possui a atribuição de efetivamente julgar o Presidente (Art.`,peg:`a divisão de funções nos processos de crime de responsabilidade (impeachment) do Presidente da República.`},
  {num:37,disc:`Constitucional`,title:`Iniciativa Popular de Leis (A fórmula 1 - 5 - 0,3)`,kw:`A FÓRMULA 1 - 5 - 0,3`,exp:`A população pode iniciar um projeto de lei federal, cumprindo rigorosamente as frações exigidas. É necessária a assinatura de no mínimo 1% do eleitorado nacional, e esse percentual deve estar espalhado por pelo menos 5 Estados, contendo, no mínimo, 0,3% dos eleitores de cada um desses Estados.`,ex:`É necessária a assinatura de no mínimo 1% do eleitorado nacional, e esse percentual deve estar espalhado por pelo menos 5 Estados, contendo, no mínimo, 0,3% dos eleitores de cada um desses Estados.`,peg:`A população pode iniciar um projeto de lei federal, cumprindo rigorosamente as frações exigidas.`},
  {num:38,disc:`Constitucional`,title:`Medida Provisória e Matéria Orçamentária`,kw:`MEDIDA PROVISÓRIA E MATÉRIA ORÇAMENTÁRIA`,exp:`A Medida Provisória (MP) possui severas vedações temáticas, principalmente orçamentárias. É expressamente vedado (Art. 62, §1º) utilizar MP para tratar de PPA, LDO, LOA ou créditos adicionais/suplementares, com a única exceção permitida para abertura de crédito extraordinário em caso de guerra, comoção interna ou calamidade pública.`,ex:`62, §1º) utilizar MP para tratar de PPA, LDO, LOA ou créditos adicionais/suplementares, com a única exceção permitida para abertura de crédito extraordinário em caso de guerra, comoção interna ou calamidade pública.`,peg:`A Medida Provisória (MP) possui severas vedações temáticas, principalmente orçamentárias.`},
  {num:39,disc:`Constitucional`,title:`Delegação de Competências do Presidente (Apenas três atos)`,kw:`APENAS TRÊS ATOS`,exp:`O artigo 84 da Constituição traz atos privativos do Presidente, mas ele pode delegar aos Ministros de Estado, ao PGR ou ao AGU. Pode-se delegar: 1) a expedição de decretos autônomos; 2) a concessão de indulto e comutação de penas; e 3) o provimento de cargos públicos. Vale lembrar que o ato de extinguir cargos é uma atribuição indelegável.`,ex:`Vale lembrar que o ato de extinguir cargos é uma atribuição indelegável.`,peg:`O artigo 84 da Constituição traz atos privativos do Presidente, mas ele pode delegar aos Ministros de Estado, ao PGR ou ao AGU.`},
  {num:40,disc:`Constitucional`,title:`Diferença crucial entre Graça, Indulto e Anistia`,kw:`DIFERENÇA CRUCIAL ENTRE GRAÇA, INDULTO`,exp:`Para não confundir na prova: o Indulto é o perdão coletivo da pena, enquanto a Graça é individual, e ambos são concedidos via decreto pelo Presidente da República. Já a Anistia apaga os efeitos do crime (primários e secundários) de forma coletiva, e somente é concedida por meio de lei aprovada pelo Congresso Nacional.`,ex:`Já a Anistia apaga os efeitos do crime (primários e secundários) de forma coletiva, e somente é concedida por meio de lei aprovada pelo Congresso Nacional.`,peg:`Para não confundir na prova: o Indulto é o perdão coletivo da pena, enquanto a Graça é individual, e ambos são concedidos via decreto pelo Presidente da República.`},
  {num:41,disc:`Constitucional`,title:`O Quinto Constitucional (Ingresso nos Tribunais)`,kw:`INGRESSO NOS TRIBUNAIS`,exp:`Pelo Art. 94 da Constituição, 1/5 (20%) dos assentos em tribunais (como TRF, TJ, TST) são reservados a advogados e membros do Ministério Público. Os requisitos cumulativos são: mais de 10 anos de atividade profissional/carreira, notável saber jurídico e reputação ilibada. O órgão de classe forma lista sêxtupla, o Tribunal enxuga para tríplice e o Chefe do Executivo escolhe quem nomear.`,ex:`O órgão de classe forma lista sêxtupla, o Tribunal enxuga para tríplice e o Chefe do Executivo escolhe quem nomear.`,peg:`94 da Constituição, 1/5 (20%) dos assentos em tribunais (como TRF, TJ, TST) são reservados a advogados e membros do Ministério Público.`},
  {num:42,disc:`Constitucional`,title:`Estado de Defesa x Estado de Sítio`,kw:`ESTADO DE DEFESA X ESTADO`,exp:`O Estado de Defesa atende crises de ordem pública em locais restritos e determinados, tem duração de 30 dias (prorrogáveis por igual período) e seu controle político pelo Congresso é feito de forma posterior. Em contraponto, o Estado de Sítio aplica-se a comoções com repercussão nacional ou guerra armada e o Congresso atua com controle prévio, pois exige autorização antecedente. ADMINISTRATIVO`,ex:`Em contraponto, o Estado de Sítio aplica-se a comoções com repercussão nacional ou guerra armada e o Congresso atua com controle prévio, pois exige autorização antecedente.`,peg:`O Estado de Defesa atende crises de ordem pública em locais restritos e determinados, tem duração de 30 dias (prorrogáveis por igual período) e seu controle político pelo Congresso é feito de forma posterior.`},
  {num:43,disc:`Administrativo`,title:`Autarquias x Empresas Estatais (A Pegadinha da Natureza Jurídica)`,kw:`AUTARQUIA=PÚBLICO / ESTATAL=PRIVADO`,exp:`As Autarquias são pessoas jurídicas de Direito Público, o que significa que seus bens são impenhoráveis e seus servidores podem ter estabilidade. Já as Empresas Públicas e as Sociedades de Economia Mista são pessoas jurídicas de Direito Privado, portanto, seus bens podem ser penhorados e seus empregados são regidos pela CLT, sem estabilidade.`,ex:`Empresa Pública: empregados CLT, bens penhoráveis.`,peg:`Atribuir características de autarquia às empresas estatais.`},
  {num:44,disc:`Administrativo`,title:`Usucapião de Bens Públicos? NUNCA!`,kw:`USUCAPIÃO DE BENS PÚBLICOS? NUNCA!`,exp:`A prova da FGV adora contar uma história longa e emocionante sobre ocupação irregular, mas seja firme: bens públicos são imprescritíveis e jamais podem ser adquiridos por usucapião. A ocupação irregular configura apenas mera detenção, não gerando direito a indenização ou retenção por benfeitorias.`,ex:`A ocupação irregular configura apenas mera detenção, não gerando direito a indenização ou retenção por benfeitorias.`,peg:`A prova da FGV adora contar uma história longa e emocionante sobre ocupação irregular, mas seja firme: bens públicos são imprescritíveis e jamais podem ser adquiridos por usucapião.`},
  {num:45,disc:`Administrativo`,title:`O Momento da Exigência dos Requisitos do Concurso`,kw:`O MOMENTO DA EXIGÊNCIA DOS`,exp:`A comprovação dos requisitos para ingresso em cargo público (como diploma de graduação ou inscrição na OAB) deve ser exigida apenas no momento da posse, e não durante a inscrição do concurso público.`,ex:`A comprovação dos requisitos para ingresso em cargo público (como diploma de graduação ou inscrição na OAB) deve ser exigida apenas no momento da poss`,peg:`A comprovação dos requisitos para ingresso em cargo público (como diploma de graduação ou inscrição na OAB) deve ser exigida apenas no momento da posse, e não durante a inscrição do concurso público.`},
  {num:46,disc:`Administrativo`,title:`Independência de Instâncias e o Art. 126 da Lei 8.112/90`,kw:`INDEPENDÊNCIA DE INSTÂNCIAS E O`,exp:`A absolvição do servidor na esfera criminal (como por "falta de provas" ou prescrição) não encerra automaticamente o Processo Administrativo Disciplinar (PAD). O processo criminal só arquiva o PAD em duas situações específicas: inexistência do fato ou negativa de autoria.`,ex:`O processo criminal só arquiva o PAD em duas situações específicas: inexistência do fato ou negativa de autoria.`,peg:`A absolvição do servidor na esfera criminal (como por "falta de provas" ou prescrição) não encerra automaticamente o Processo Administrativo Disciplinar (PAD).`},
  {num:47,disc:`Administrativo`,title:`A "Pegadinha" do Advogado no PAD`,kw:`A "PEGADINHA" DO ADVOGADO NO`,exp:`Em Direito Administrativo, a presença de advogado não é obrigatória no Processo Administrativo Disciplinar (PAD). A falta de defesa técnica por advogado não torna o PAD nulo, conforme expressa previsão da Súmula Vinculante 5 do STF.`,ex:`A falta de defesa técnica por advogado não torna o PAD nulo, conforme expressa previsão da Súmula Vinculante 5 do STF.`,peg:`Em Direito Administrativo, a presença de advogado não é obrigatória no Processo Administrativo Disciplinar (PAD).`},
  {num:48,disc:`Administrativo`,title:`Improbidade Administrativa - O Fim da Culpa`,kw:`IMPROBIDADE ADMINISTRATIVA - O FIM`,exp:`Com as alterações na Lei nº 8.429/1992 (Lei de Improbidade Administrativa - LIA), o elemento subjetivo para a condenação exige somente o dolo. Não existe mais a previsão de responsabilização por ato de improbidade na modalidade culposa.`,ex:`Não existe mais a previsão de responsabilização por ato de improbidade na modalidade culposa.`,peg:`Com as alterações na Lei nº 8.`},
  {num:49,disc:`Administrativo`,title:`Punições "Aliviadas" no Art. 11 da LIA`,kw:`PUNIÇÕES "ALIVIADAS" NO ART. 11`,exp:`Fique atento à mudança recente! Para os atos de improbidade que atentam apenas contra os princípios da administração (Art. 11), não há mais aplicação das penas de perda da função pública e suspensão dos direitos políticos. A sanção foca em multas e ressarcimento.`,ex:`A sanção foca em multas e ressarcimento.`,peg:`à mudança recente! Para os atos de improbidade que atentam apenas contra os princípios da administração (Art.`},
  {num:50,disc:`Administrativo`,title:`Lei Anticorrupção (Lei 12.846/2013) NUNCA é Penal`,kw:`LEI 12.846/2013`,exp:`A Lei Anticorrupção tem como alvo a responsabilização objetiva da pessoa jurídica (empresa) em duas esferas exclusivas: Administrativa e Civil. O macete é lembrar que a pessoa jurídica não responde penalmente/criminalmente com base nesta lei.`,ex:`O macete é lembrar que a pessoa jurídica não responde penalmente/criminalmente com base nesta lei.`,peg:`lembrar que a pessoa jurídica não responde penalmente/criminalmente com base nesta lei.`},
  {num:51,disc:`Administrativo`,title:`Acordo de Leniência (O Primeiro "Dedo-Duro")`,kw:`O PRIMEIRO "DEDO-DURO"`,exp:`Para a empresa assinar um Acordo de Leniência na Lei Anticorrupção, os requisitos são cumulativos: confessar, cessar seu envolvimento na fraude e ser a PRIMEIRA a manifestar interesse. Lembre-se, contudo, que fechar o acordo não a isenta da obrigação de reparar integralmente o dano ao erário.`,ex:`Lembre-se, contudo, que fechar o acordo não a isenta da obrigação de reparar integralmente o dano ao erário.`,peg:`Para a empresa assinar um Acordo de Leniência na Lei Anticorrupção, os requisitos são cumulativos: confessar, cessar seu envolvimento na fraude e ser a PRIMEIRA a manifestar interesse.`},
  {num:52,disc:`Administrativo`,title:`O Fim do Convite e Tomada de Preços`,kw:`O FIM DO CONVITE E`,exp:`A Nova Lei de Licitações (Lei nº 14.133/2021) abandonou a divisão de modalidades baseada no valor do contrato. Não existem mais as modalidades Convite e Tomada de Preços. Foram mantidos Pregão, Concorrência, Concurso, Leilão, além da criação do Diálogo Competitivo.`,ex:`Foram mantidos Pregão, Concorrência, Concurso, Leilão, além da criação do Diálogo Competitivo.`,peg:`A Nova Lei de Licitações (Lei nº 14.`},
  {num:53,disc:`Administrativo`,title:`Princípio da Segregação de Funções`,kw:`PRINCÍPIO DA SEGREGAÇÃO DE FUNÇÕES`,exp:`Na Nova Lei de Licitações (14.133/21), o princípio da Segregação das Funções proíbe que um mesmo agente público acumule funções de risco no procedimento (ex: quem prepara o edital não pode julgar). A banca pode tentar te confundir usando a palavra "agregação", mas o correto é separar.`,ex:`A banca pode tentar te confundir usando a palavra "agregação", mas o correto é separar.`,peg:`pode tentar te confundir usando a palavra "agregação", mas o correto é separar.`},
  {num:54,disc:`Administrativo`,title:`Inexigibilidade x Dispensa de Licitação`,kw:`INEXIGIBILIDADE X DISPENSA DE LICITAÇÃO`,exp:`Se a competição for inviável, a licitação é inexigível. O macete é decorar os 5 casos principais da Nova Lei: fornecedor exclusivo, artista consagrado, profissional de notória especialização (exceto para serviços de publicidade), credenciamento e imóvel singular. Nos demais casos comuns (baixo valor, emergência, deserta), a licitação é apenas dispensável.`,ex:`Nos demais casos comuns (baixo valor, emergência, deserta), a licitação é apenas dispensável.`,peg:`decorar os 5 casos principais da Nova Lei: fornecedor exclusivo, artista consagrado, profissional de notória especialização (exceto para serviços de publicidade), credenciamento e imóvel singular.`},
  {num:55,disc:`Administrativo`,title:`Responsabilidade Civil por Fuga de Preso e Balas Perdidas`,kw:`RESPONSABILIDADE CIVIL POR FUGA DE`,exp:`O Estado possui responsabilidade objetiva sobre detentos (Teoria do Risco). Se o preso foragido cometer um crime durante ou imediatamente após a fuga, o Estado responde por haver nexo causal. Se o crime ocorrer meses ou anos depois, o nexo rompe e o Estado não paga. Já em mortes por bala perdida em operações policiais, a responsabilidade do Estado é reconhecida mesmo que a perícia da arma seja inconclusiva.`,ex:`Já em mortes por bala perdida em operações policiais, a responsabilidade do Estado é reconhecida mesmo que a perícia da arma seja inconclusiva.`,peg:`O Estado possui responsabilidade objetiva sobre detentos (Teoria do Risco).`},
  {num:56,disc:`Administrativo`,title:`Extinção da Concessão de Serviços (A Regra dos Três Nomes)`,kw:`A REGRA DOS TRÊS NOMES`,exp:`Use as palavraschave para não confundir: Encampação = Retomada do serviço pelo Estado por motivo de interesse público (exige lei específica e pagamento prévio). Caducidade = Descumprimento das regras pela concessionária (aplicada por decreto, como punição). Rescisão = Inadimplência ou culpa do poder público, declarada judicialmente.`,ex:`Rescisão = Inadimplência ou culpa do poder público, declarada judicialmente.`,peg:`Use as palavraschave para não confundir: Encampação = Retomada do serviço pelo Estado por motivo de interesse público (exige lei específica e pagamento prévio).`},
  {num:57,disc:`Administrativo`,title:`Desapropriação Indireta (A Invasão Estatal)`,kw:`A INVASÃO ESTATAL`,exp:`Ocorre quando o Estado "toma" um bem sem o devido processo legal e incorpora-o ao patrimônio público. A ação para o particular cobrar sua indenização (já que não pode mais pedir o bem de volta) prescreve em 10 anos caso o Estado tenha realizado obra pública no local, ou 15 anos caso não tenha realizado obra. CIVIL`,ex:`A ação para o particular cobrar sua indenização (já que não pode mais pedir o bem de volta) prescreve em 10 anos caso o Estado tenha realizado obra pública no local, ou 15 anos caso não tenha realizado obra.`,peg:`Ocorre quando o Estado "toma" um bem sem o devido processo legal e incorpora-o ao patrimônio público.`},
  {num:58,disc:`Civil`,title:`Incapacidade Absoluta e Relativa (A diferença dos efeitos)`,kw:`MENOR 16=NULO / 16-18=ANULÁVEL`,exp:`Atualmente, são considerados absolutamente incapazes apenas os menores de 16 anos, e os atos praticados por eles sem representação legal são nulos. Já os atos praticados por relativamente incapazes (como maiores de 16 e menores de 18 anos) sem assistência são apenas anuláveis.`,ex:`Adolescente de 15 anos assina contrato sozinho: ato nulo.`,peg:`Confundir nulo com anulável.`},
  {num:59,disc:`Civil`,title:`Emancipação Voluntária (O macete do cartório)`,kw:`O MACETE DO CARTÓRIO`,exp:`A emancipação concedida pelos pais a um menor que já tenha 16 anos completos é feita por instrumento público (escritura pública) e independe de homologação judicial.`,ex:`A emancipação concedida pelos pais a um menor que já tenha 16 anos completos é feita por instrumento público (escritura pública) e independe de homolo`,peg:`A emancipação concedida pelos pais a um menor que já tenha 16 anos completos é feita por instrumento público (escritura pública) e independe de homologação judicial.`},
  {num:60,disc:`Civil`,title:`Morte Presumida (A dispensa de ausência prévia)`,kw:`A DISPENSA DE AUSÊNCIA PRÉVIA`,exp:`É possível declarar a morte presumida sem a necessidade de decretar ausência antes, desde que esgotadas as buscas, em dois casos específicos: quando for extremamente provável a morte de alguém em perigo de vida ou quando a pessoa desaparecer em campanha de guerra e não for encontrada até dois anos após o seu término.`,ex:`É possível declarar a morte presumida sem a necessidade de decretar ausência antes, desde que esgotadas as buscas, em dois casos específicos: quando f`,peg:`É possível declarar a morte presumida sem a necessidade de decretar ausência antes, desde que esgotadas as buscas, em dois casos específicos: quando for extremamente provável a morte de alguém em perigo de vida ou quando a pessoa desaparecer em campa`},
  {num:61,disc:`Civil`,title:`A Escritura Pública nos Negócios Imobiliários`,kw:`A ESCRITURA PÚBLICA NOS NEGÓCIOS`,exp:`A regra geral é a liberdade de forma nos contratos, mas a escritura pública é essencial para a validade de negócios que envolvam transferência ou constituição de direitos reais sobre imóveis cujo valor seja superior a 30 vezes o maior salário mínimo do país.`,ex:`A regra geral é a liberdade de forma nos contratos, mas a escritura pública é essencial para a validade de negócios que envolvam transferência ou cons`,peg:`A regra geral é a liberdade de forma nos contratos, mas a escritura pública é essencial para a validade de negócios que envolvam transferência ou constituição de direitos reais sobre imóveis cujo valor seja superior a 30 vezes o maior salário mínimo `},
  {num:62,disc:`Civil`,title:`Simulação gera Nulidade, não Anulabilidade`,kw:`SIMULAÇÃO GERA NULIDADE, NÃO ANULABILIDA`,exp:`Cuidado com as pegadinhas nos defeitos do negócio jurídico. Erro, dolo, coação, estado de perigo, lesão e fraude contra credores geram anulabilidade (com prazo decadencial de 4 anos). A simulação, por sua vez, é um vício muito mais grave que gera a nulidade absoluta do negócio, não convalescendo pelo decurso do tempo.`,ex:`A simulação, por sua vez, é um vício muito mais grave que gera a nulidade absoluta do negócio, não convalescendo pelo decurso do tempo.`,peg:`com as pegadinhas nos defeitos do negócio jurídico.`},
  {num:63,disc:`Civil`,title:`Concentração nas Obrigações de Dar Coisa Incerta`,kw:`CONCENTRAÇÃO NAS OBRIGAÇÕES DE DAR`,exp:`O macete clássico baseia-se no princípio de que "o gênero nunca perece". Antes da escolha ser feita, o devedor não pode alegar perda da coisa por caso fortuito ou força maior. A regra geral é que a escolha pertence ao devedor, salvo estipulação em contrário no contrato.`,ex:`A regra geral é que a escolha pertence ao devedor, salvo estipulação em contrário no contrato.`,peg:`O macete clássico baseia-se no princípio de que "o gênero nunca perece".`},
  {num:64,disc:`Civil`,title:`A Pegadinha da Solidariedade e da Indivisibilidade`,kw:`A PEGADINHA DA SOLIDARIEDADE E`,exp:`A solidariedade não se presume, ela deve resultar expressamente da lei ou da vontade das partes (contrato). Além disso, se uma obrigação indivisível for resolvida em perdas e danos, ela perde a sua qualidade de indivisível, passando a ser uma obrigação pecuniária (divisível).`,ex:`Além disso, se uma obrigação indivisível for resolvida em perdas e danos, ela perde a sua qualidade de indivisível, passando a ser uma obrigação pecuniária (divisível).`,peg:`A solidariedade não se presume, ela deve resultar expressamente da lei ou da vontade das partes (contrato).`},
  {num:65,disc:`Civil`,title:`Prazos dos Vícios Redibitórios`,kw:`PRAZOS DOS VÍCIOS REDIBITÓRIOS`,exp:`Para reclamar defeitos ocultos (redibir o contrato ou abater preço), o prazo decadencial, contado da entrega efetiva, é de 30 dias para bens móveis e 1 ano para bens imóveis. Se o adquirente já estava na posse do bem antes, esses prazos caem pela metade.`,ex:`Se o adquirente já estava na posse do bem antes, esses prazos caem pela metade.`,peg:`Para reclamar defeitos ocultos (redibir o contrato ou abater preço), o prazo decadencial, contado da entrega efetiva, é de 30 dias para bens móveis e 1 ano para bens imóveis.`},
  {num:66,disc:`Civil`,title:`Evicção (A Cláusula de Exclusão não é absoluta)`,kw:`A CLÁUSULA DE EXCLUSÃO NÃO É ABSOLUTA`,exp:`O alienante responde pela perda da coisa por decisão judicial (evicção), mas as partes podem pactuar sua exclusão. O macete é: mesmo havendo cláusula de exclusão, se o adquirente não sabia do risco ou não o assumiu, ele ainda tem o direito de receber de volta o preço que pagou pela coisa evicta.`,ex:`O macete é: mesmo havendo cláusula de exclusão, se o adquirente não sabia do risco ou não o assumiu, ele ainda tem o direito de receber de volta o preço que pagou pela coisa evicta.`,peg:`mesmo havendo cláusula de exclusão, se o adquirente não sabia do risco ou não o assumiu, ele ainda tem o direito de receber de volta o preço que pagou pela coisa evicta.`},
  {num:67,disc:`Civil`,title:`A Exceção da Doação Verbal`,kw:`A EXCEÇÃO DA DOAÇÃO VERBAL`,exp:`A doação, em regra, exige escritura pública ou instrumento particular. Contudo, a prova adora a exceção: a doação verbal é válida desde que cumpra dois requisitos cumulativos: verse sobre bens móveis de pequeno valor e seja seguida da tradição imediata (entrega) do bem.`,ex:`Contudo, a prova adora a exceção: a doação verbal é válida desde que cumpra dois requisitos cumulativos: verse sobre bens móveis de pequeno valor e seja seguida da tradição imediata (entrega) do bem.`,peg:`A doação, em regra, exige escritura pública ou instrumento particular.`},
  {num:68,disc:`Civil`,title:`Revogação de Doação por Ingratidão (As exceções)`,kw:`AS EXCEÇÕES`,exp:`O doador tem o prazo de 1 ano para revogar a doação por ingratidão (ex: atentado contra sua vida ou recusa de alimentos). No entanto, fique atento ao que NÃO se revoga por ingratidão: doações puramente remuneratórias, doações com encargo já cumprido e doações feitas para determinado casamento.`,ex:`No entanto, fique atento ao que NÃO se revoga por ingratidão: doações puramente remuneratórias, doações com encargo já cumprido e doações feitas para determinado casamento.`,peg:`ao que NÃO se revoga por ingratidão: doações puramente remuneratórias, doações com encargo já cumprido e doações feitas para determinado casamento.`},
  {num:69,disc:`Civil`,title:`Comodato x Mútuo`,kw:`COMODATO X MÚTUO`,exp:`Lembre-se da diferença pelos riscos e pela fungibilidade. O Comodato é o empréstimo gratuito de coisas infungíveis (só o uso). O Mútuo é o empréstimo de coisas fungíveis; como ele transfere o domínio (a propriedade) da coisa, o mutuário passa a assumir todos os riscos a partir do momento da entrega.`,ex:`O Mútuo é o empréstimo de coisas fungíveis; como ele transfere o domínio (a propriedade) da coisa, o mutuário passa a assumir todos os riscos a partir do momento da entrega.`,peg:`da diferença pelos riscos e pela fungibilidade.`},
  {num:70,disc:`Civil`,title:`Responsabilidade Civil Objetiva do Empregador`,kw:`RESPONSABILIDADE CIVIL OBJETIVA DO EMPRE`,exp:`Embora a regra geral da responsabilidade seja subjetiva (baseada na culpa), o Código Civil impõe responsabilidade objetiva (independente de culpa) a certas pessoas por atos de terceiros. Por exemplo: o empregador responde objetivamente pelos atos de seus empregados no exercício do trabalho, os pais pelos filhos menores, e os donos de hotéis pelos hóspedes.`,ex:`Por exemplo: o empregador responde objetivamente pelos atos de seus empregados no exercício do trabalho, os pais pelos filhos menores, e os donos de hotéis pelos hóspedes.`,peg:`Embora a regra geral da responsabilidade seja subjetiva (baseada na culpa), o Código Civil impõe responsabilidade objetiva (independente de culpa) a certas pessoas por atos de terceiros.`},
  {num:71,disc:`Civil`,title:`A Vinculação da Esfera Criminal no Cível`,kw:`A VINCULAÇÃO DA ESFERA CRIMINAL`,exp:`A responsabilidade civil é independente da criminal. Porém, se o juiz criminal julgar o caso e decidir categoricamente sobre a existência do fato ou sobre quem foi o autor do crime, essas questões fecham as portas da Justiça Cível e não podem mais ser discutidas ou alteradas lá.`,ex:`Porém, se o juiz criminal julgar o caso e decidir categoricamente sobre a existência do fato ou sobre quem foi o autor do crime, essas questões fecham as portas da Justiça Cível e não podem mais ser discutidas ou alteradas lá.`,peg:`A responsabilidade civil é independente da criminal.`},
  {num:72,disc:`Civil`,title:`Direito de Retenção e Benfeitorias`,kw:`DIREITO DE RETENÇÃO E BENFEITORIAS`,exp:`O possuidor de boa-fé tem direito à indenização das benfeitorias necessárias e úteis, podendo exercer o direito de retenção do bem para garantir o pagamento. O possuidor de má-fé, como uma forma de sanção, tem direito apenas de receber de volta o que gastou com benfeitorias necessárias e não possui direito de retenção de forma alguma.`,ex:`O possuidor de má-fé, como uma forma de sanção, tem direito apenas de receber de volta o que gastou com benfeitorias necessárias e não possui direito de retenção de forma alguma.`,peg:`O possuidor de boa-fé tem direito à indenização das benfeitorias necessárias e úteis, podendo exercer o direito de retenção do bem para garantir o pagamento.`},
  {num:73,disc:`Civil`,title:`Usucapião Familiar`,kw:`USUCAPIÃO FAMILIAR`,exp:`Essa modalidade possui um prazo muito curto, de apenas 2 anos ininterruptos. Exige a posse de imóvel urbano de até 250 m², cuja propriedade era dividida com o ex-cônjuge ou ex-companheiro que tenha abandonado o lar. O ocupante não pode possuir outro imóvel e esse direito só é concedido uma única vez.`,ex:`O ocupante não pode possuir outro imóvel e esse direito só é concedido uma única vez.`,peg:`Essa modalidade possui um prazo muito curto, de apenas 2 anos ininterruptos.`},
  {num:74,disc:`Civil`,title:`A Exceção da Outorga Conjugal`,kw:`A EXCEÇÃO DA OUTORGA CONJUGAL`,exp:`Nenhum dos cônjuges pode vender imóveis, prestar fiança ou aval sem a autorização do outro (o que tornaria o ato anulável). A única exceção legal que dispensa absolutamente essa outorga conjugal é quando o casamento for regido pelo regime da separação absoluta de bens.`,ex:`A única exceção legal que dispensa absolutamente essa outorga conjugal é quando o casamento for regido pelo regime da separação absoluta de bens.`,peg:`Nenhum dos cônjuges pode vender imóveis, prestar fiança ou aval sem a autorização do outro (o que tornaria o ato anulável).`},
  {num:75,disc:`Civil`,title:`Sucessão e Direito de Representação`,kw:`SUCESSÃO E DIREITO DE REPRESENTAÇÃO`,exp:`O direito de representação permite que um parente herde no lugar do herdeiro pré-morto. O macete para gabaritar: a representação ocorre na linha reta descendente (netos representam filhos pré-mortos), mas NUNCA na linha reta ascendente (pais não herdam no lugar de avós). Na linha colateral, a lei permite o benefício apenas para os filhos de irmãos do falecido (os sobrinhos). PROCESSO CIVIL 18 Macetes para Gabaritar Direito Processual Civil na OAB`,ex:`PROCESSO CIVIL 18 Macetes para Gabaritar Direito Processual Civil na OAB.`,peg:`gabaritar: a representação ocorre na linha reta descendente (netos representam filhos pré-mortos), mas NUNCA na linha reta ascendente (pais não herdam no lugar de avós).`},
  {num:76,disc:`Processo Civil`,title:`Curador Especial (A Regra dos Revels)`,kw:`A REGRA DOS REVELS`,exp:`O juiz é obrigado a nomear curador especial não apenas para os incapazes sem representante, mas também para o réu preso revel e para o réu revel citado por edital ou com hora certa, enquanto não constituírem advogado. (Art. 72 do CPC).`,ex:`O juiz é obrigado a nomear curador especial não apenas para os incapazes sem representante, mas também para o réu preso revel e para o réu revel citad`,peg:`O juiz é obrigado a nomear curador especial não apenas para os incapazes sem representante, mas também para o réu preso revel e para o réu revel citado por edital ou com hora certa, enquanto não constituírem advogado.`},
  {num:77,disc:`Processo Civil`,title:`Citação de Cônjuges e Ações Imobiliárias`,kw:`CITAÇÃO DE CÔNJUGES E AÇÕES`,exp:`A citação de ambos os cônjuges é obrigatória em ações que versem sobre direito real imobiliário. A única exceção a essa regra é se o casal for casado sob o regime de separação absoluta de bens. (Art. 73 do CPC).`,ex:`A única exceção a essa regra é se o casal for casado sob o regime de separação absoluta de bens.`,peg:`A citação de ambos os cônjuges é obrigatória em ações que versem sobre direito real imobiliário.`},
  {num:78,disc:`Processo Civil`,title:`Multa por Ato Atentatório à Dignidade da Justiça`,kw:`MULTA POR ATO ATENTATÓRIO À`,exp:`Fique atento à pegadinha! Se houver descumprimento de decisões judiciais, o juiz pode aplicar multa de até 20% do valor da causa. Contudo, essa multa não se aplica aos advogados (públicos ou privados), membros da Defensoria Pública e do Ministério Público. A responsabilidade deles é apurada por seus respectivos órgãos de classe. (Art. 77, § 6º do CPC).`,ex:`A responsabilidade deles é apurada por seus respectivos órgãos de classe.`,peg:`à pegadinha! Se houver descumprimento de decisões judiciais, o juiz pode aplicar multa de até 20% do valor da causa.`},
  {num:79,disc:`Processo Civil`,title:`Renúncia ao Mandato pelo Advogado`,kw:`RENÚNCIA AO MANDATO PELO ADVOGADO`,exp:`Se o advogado decidir renunciar ao mandato, ele deve comunicar o cliente e continuará o representando pelos 10 (dez) dias seguintes, para evitar prejuízos. A comunicação só é dispensada se a procuração tiver sido outorgada a vários advogados e a parte continuar sendo representada por outro profissional no processo. (Art. 112 do CPC).`,ex:`A comunicação só é dispensada se a procuração tiver sido outorgada a vários advogados e a parte continuar sendo representada por outro profissional no processo.`,peg:`Se o advogado decidir renunciar ao mandato, ele deve comunicar o cliente e continuará o representando pelos 10 (dez) dias seguintes, para evitar prejuízos.`},
  {num:80,disc:`Processo Civil`,title:`Limitação do Litisconsórcio Facultativo (Multidão no Processo)`,kw:`MULTIDÃO NO PROCESSO`,exp:`O juiz pode limitar o número de pessoas no litisconsórcio facultativo (seja na fase de conhecimento, liquidação ou execução) se a quantidade de partes estiver atrapalhando a rápida solução do conflito. Esse pedido de limitação interrompe o prazo para resposta. (Art. 113, § 1º do CPC).`,ex:`Esse pedido de limitação interrompe o prazo para resposta.`,peg:`O juiz pode limitar o número de pessoas no litisconsórcio facultativo (seja na fase de conhecimento, liquidação ou execução) se a quantidade de partes estiver atrapalhando a rápida solução do conflito.`},
  {num:81,disc:`Processo Civil`,title:`O Perigo do Litisconsórcio Necessário`,kw:`O PERIGO DO LITISCONSÓRCIO NECESSÁRIO`,exp:`Se um litisconsorte necessário obrigatório deixar de ser citado, há duas consequências possíveis ditadas pela prova: se a decisão deveria ser uniforme para todos (litisconsórcio unitário), a sentença de mérito será nula. Se não precisasse ser uniforme, a sentença será apenas ineficaz para aquele que não foi citado. (Art. 115 do CPC).`,ex:`Se não precisasse ser uniforme, a sentença será apenas ineficaz para aquele que não foi citado.`,peg:`Se um litisconsorte necessário obrigatório deixar de ser citado, há duas consequências possíveis ditadas pela prova: se a decisão deveria ser uniforme para todos (litisconsórcio unitário), a sentença de mérito será nula.`},
  {num:82,disc:`Processo Civil`,title:`Denunciação da Lide Sucessiva`,kw:`DENUNCIAÇÃO DA LIDE SUCESSIVA`,exp:`A lei permite apenas uma única denunciação sucessiva. Se o denunciado (quem foi chamado ao processo) chamar o seu antecessor para responder, este segundo denunciado não poderá fazer uma nova denunciação; ele deverá buscar seu direito de regresso através de uma ação autônoma. (Art. 125, § 2º do CPC).`,ex:`Se o denunciado (quem foi chamado ao processo) chamar o seu antecessor para responder, este segundo denunciado não poderá fazer uma nova denunciação; ele deverá buscar seu direito de regresso através de uma ação autônoma.`,peg:`A lei permite apenas uma única denunciação sucessiva.`},
  {num:83,disc:`Processo Civil`,title:`O Objetivo do Chamamento ao Processo`,kw:`O OBJETIVO DO CHAMAMENTO AO`,exp:`Usado geralmente em casos de fiadores e devedores solidários, o grande macete do chamamento é que a sentença que der razão ao autor servirá como título executivo a favor do réu que pagar a dívida. Ele poderá usar a mesma sentença para cobrar a cota-parte dos demais codevedores que chamou ao processo. (Art. 130 do CPC).`,ex:`Ele poderá usar a mesma sentença para cobrar a cota-parte dos demais codevedores que chamou ao processo.`,peg:`Usado geralmente em casos de fiadores e devedores solidários, o grande macete do chamamento é que a sentença que der razão ao autor servirá como título executivo a favor do réu que pagar a dívida.`},
  {num:84,disc:`Processo Civil`,title:`Estabilização da Tutela Antecipada Antecedente`,kw:`ESTABILIZAÇÃO DA TUTELA ANTECIPADA ANTEC`,exp:`Se o juiz conceder a tutela antecipada em caráter antecedente e a parte contrária não interpor o respectivo recurso, a decisão torna-se estável e o processo é extinto. Importante: essa estabilização não faz coisa julgada material e pode ser revista através de ação própria no prazo decadencial de 2 anos. (Art. 304 do CPC).`,ex:`Importante: essa estabilização não faz coisa julgada material e pode ser revista através de ação própria no prazo decadencial de 2 anos.`,peg:`Se o juiz conceder a tutela antecipada em caráter antecedente e a parte contrária não interpor o respectivo recurso, a decisão torna-se estável e o processo é extinto.`},
  {num:85,disc:`Processo Civil`,title:`Tutela da Evidência (A Dispensa do Perigo)`,kw:`A DISPENSA DO PERIGO`,exp:`Diferente das tutelas de urgência, para a concessão da tutela da evidência não é necessário demonstrar perigo de dano ou risco ao resultado útil do processo. Basta que o direito seja extremamente claro, como em casos de tese firmada em julgamento de recursos repetitivos ou súmula vinculante (podendo ser concedida liminarmente). (Art. 311 do CPC).`,ex:`Basta que o direito seja extremamente claro, como em casos de tese firmada em julgamento de recursos repetitivos ou súmula vinculante (podendo ser concedida liminarmente).`,peg:`Diferente das tutelas de urgência, para a concessão da tutela da evidência não é necessário demonstrar perigo de dano ou risco ao resultado útil do processo.`},
  {num:86,disc:`Processo Civil`,title:`Audiência de Conciliação e o "Desinteresse"`,kw:`AUDIÊNCIA DE CONCILIAÇÃO E O`,exp:`Para que a audiência inicial de conciliação NÃO aconteça, é necessário que ambas as partes (autor e réu) manifestem expressamente o desinteresse. O autor avisa logo na petição inicial, e o réu deve fazer o pedido de cancelamento por petição com 10 dias de antecedência. O não comparecimento injustificado gera multa de até 2%. (Art. 334 do CPC).`,ex:`O não comparecimento injustificado gera multa de até 2%.`,peg:`Para que a audiência inicial de conciliação NÃO aconteça, é necessário que ambas as partes (autor e réu) manifestem expressamente o desinteresse.`},
  {num:87,disc:`Processo Civil`,title:`Improcedência Liminar do Pedido`,kw:`IMPROCEDÊNCIA LIMINAR DO PEDIDO`,exp:`Em causas que não precisem de produção de novas provas, o juiz pode julgar o caso como improcedente liminarmente (antes mesmo de citar o réu) se o pedido contrariar Súmulas do STF/STJ, Acórdãos em Recursos Repetitivos, IRDR, ou se o juiz reconhecer de cara a ocorrência de decadência ou prescrição. (Art. 332 do CPC).`,ex:`Em causas que não precisem de produção de novas provas, o juiz pode julgar o caso como improcedente liminarmente (antes mesmo de citar o réu) se o ped`,peg:`Em causas que não precisem de produção de novas provas, o juiz pode julgar o caso como improcedente liminarmente (antes mesmo de citar o réu) se o pedido contrariar Súmulas do STF/STJ, Acórdãos em Recursos Repetitivos, IRDR, ou se o juiz reconhecer d`},
  {num:88,disc:`Processo Civil`,title:`Distribuição Dinâmica do Ônus da Prova`,kw:`DISTRIBUIÇÃO DINÂMICA DO ÔNUS DA`,exp:`A regra geral é de que o autor prova o direito e o réu prova os fatos impeditivos/modificativos. No entanto, o juiz pode redistribuir esse ônus em decisão fundamentada se houver impossibilidade técnica ou maior facilidade de obtenção da prova pela outra parte. A vedação é que o juiz não pode criar uma situação de impossibilidade de prova (a chamada "prova diabólica"). (Art. 373, § 1º do CPC).`,ex:`A vedação é que o juiz não pode criar uma situação de impossibilidade de prova (a chamada "prova diabólica").`,peg:`A regra geral é de que o autor prova o direito e o réu prova os fatos impeditivos/modificativos.`},
  {num:89,disc:`Processo Civil`,title:`Coisa Julgada (O que NÃO faz)`,kw:`O QUE NÃO FAZ`,exp:`As bancas adoram tentar te confundir com isso. Lembre-se que os motivos da sentença (os argumentos do juiz) e a verdade dos fatos estabelecida como base da decisão NÃO fazem coisa julgada; apenas a conclusão jurídica (dispositivo) é protegida por essa imutabilidade. (Art. 504 do CPC).`,ex:`Lembre-se que os motivos da sentença (os argumentos do juiz) e a verdade dos fatos estabelecida como base da decisão NÃO fazem coisa julgada; apenas a conclusão jurídica (dispositivo) é protegida por essa imutabilidade.`,peg:`As bancas adoram tentar te confundir com isso.`},
  {num:90,disc:`Processo Civil`,title:`Fraude à Execução`,kw:`FRAUDE À EXECUÇÃO`,exp:`A alienação (venda) de um bem feita em fraude à execução é considerada ineficaz em relação ao exequente. Isso significa que o negócio até existe e é válido entre comprador e vendedor, mas para o credor (exequente) e para o processo de execução, a venda simplesmente não surte efeitos, e o bem será penhorado. (Art. 792, § 1º do CPC).`,ex:`Isso significa que o negócio até existe e é válido entre comprador e vendedor, mas para o credor (exequente) e para o processo de execução, a venda simplesmente não surte efeitos, e o bem será penhorado.`,peg:`A alienação (venda) de um bem feita em fraude à execução é considerada ineficaz em relação ao exequente.`},
  {num:91,disc:`Processo Civil`,title:`Parcelamento do Débito (O Famoso Art. 916)`,kw:`O FAMOSO ART. 916`,exp:`Na execução de título extrajudicial, o executado pode pedir o parcelamento da dívida no prazo dos embargos (15 dias), depositando 30% à vista e o restante em até 6 parcelas. O macete duplo: pedir o parcelamento implica em renúncia ao direito de opor embargos à execução, e essa regra NÃO se aplica ao cumprimento de sentença. (Art. 916 do CPC).`,ex:`O macete duplo: pedir o parcelamento implica em renúncia ao direito de opor embargos à execução, e essa regra NÃO se aplica ao cumprimento de sentença.`,peg:`Na execução de título extrajudicial, o executado pode pedir o parcelamento da dívida no prazo dos embargos (15 dias), depositando 30% à vista e o restante em até 6 parcelas.`},
  {num:92,disc:`Processo Civil`,title:`Agravo de Instrumento e a Preclusão`,kw:`AGRAVO DE INSTRUMENTO E A`,exp:`O rol do Art. 1.015 para interpor Agravo de Instrumento contra decisões interlocutórias é taxativo. O macete é: se a decisão do juiz não estiver nessa lista, ela não preclui. Você deverá impugná-la preliminarmente no recurso de Apelação ou nas contrarrazões da Apelação. (Arts. 1.009, § 1º e 1.015 do CPC).`,ex:`Você deverá impugná-la preliminarmente no recurso de Apelação ou nas contrarrazões da Apelação.`,peg:`se a decisão do juiz não estiver nessa lista, ela não preclui.`},
  {num:93,disc:`Processo Civil`,title:`Embargos de Declaração (Exceção de Ouro)`,kw:`EXCEÇÃO DE OURO`,exp:`É o recurso "diferentão". Diferente do prazo geral de 15 dias para os outros recursos processuais, o prazo dos Embargos de Declaração é de apenas 5 (cinco) dias. Além disso, eles não se sujeitam a preparo (pagamento de custas), não possuem efeito suspensivo automático e interrompem o prazo para interposição de qualquer outro recurso. (Arts. 1.022 a 1.026 do CPC). PENAL`,ex:`Além disso, eles não se sujeitam a preparo (pagamento de custas), não possuem efeito suspensivo automático e interrompem o prazo para interposição de qualquer outro recurso.`,peg:`Diferente do prazo geral de 15 dias para os outros recursos processuais, o prazo dos Embargos de Declaração é de apenas 5 (cinco) dias.`},
  {num:94,disc:`Penal`,title:`Tempo e Lugar do Crime (O macete da "L.U.T.A")`,kw:`LUGAR=UBIQUIDADE / TEMPO=ATIVIDADE`,exp:`Para saber qual lei ou foro aplicar, a OAB cobra essas duas teorias. Memorize: Lugar do crime adota a teoria da Ubiquidade; Tempo do crime adota a teoria da Atividade. Ou seja, para o tempo do crime importa apenas o momento da conduta (ação ou omissão), não importando quando o resultado ocorreu. (Art. 4º e 6º do CP).`,ex:`LUTA: Lugar=Ubiquidade, Tempo=Atividade.`,peg:`Confundir as teorias.`},
  {num:95,disc:`Penal`,title:`Abolitio Criminis (O limite cível)`,kw:`O LIMITE CÍVEL`,exp:`Quando uma nova lei deixa de considerar um fato como crime (Abolitio Criminis), ela é benéfica e retroage automaticamente para fatos passados, inclusive para casos já com trânsito em julgado. Contudo, grave para a prova: ela extingue apenas os efeitos penais (réu volta a ser primário, perde maus antecedentes). Os efeitos extrapenais/cíveis (como a obrigação de indenizar a vítima) permanecem. (Art. 2º do CP / Art. 5º, XL, da CF).`,ex:`Os efeitos extrapenais/cíveis (como a obrigação de indenizar a vítima) permanecem.`,peg:`para a prova: ela extingue apenas os efeitos penais (réu volta a ser primário, perde maus antecedentes).`},
  {num:96,disc:`Penal`,title:`Extraterritorialidade Incondicionada x Condicionada`,kw:`EXTRATERRITORIALIDADE INCONDICIONADA X C`,exp:`Na incondicionada, a lei brasileira aplica-se aos crimes no exterior independentemente de o agente ter sido absolvido ou condenado no estrangeiro (ex: contra a vida do Presidente, ou genocídio por brasileiro). Já na condicionada, a lei do Brasil só se aplica se cumpridos certos requisitos cumulativos, sendo um dos principais não ter sido o agente absolvido no estrangeiro ou não ter lá cumprido a pena. (Art. 7º, I, II e § 2º do CP).`,ex:`Já na condicionada, a lei do Brasil só se aplica se cumpridos certos requisitos cumulativos, sendo um dos principais não ter sido o agente absolvido no estrangeiro ou não ter lá cumprido a pena.`,peg:`Na incondicionada, a lei brasileira aplica-se aos crimes no exterior independentemente de o agente ter sido absolvido ou condenado no estrangeiro (ex: contra a vida do Presidente, ou genocídio por brasileiro).`},
  {num:97,disc:`Penal`,title:`A Pegadinha da Coação (Física x Moral)`,kw:`FÍSICA X MORAL`,exp:`Na coação física irresistível (ex: forçar fisicamente a mão de alguém para apertar o gatilho), exclui-se a própria conduta e, consequentemente, afasta-se o Fato Típico. Já na coação moral irresistível (uma grave ameaça, como "mate o caixa ou mato sua família"), a conduta existe, mas há exclusão da culpabilidade por inexigibilidade de conduta diversa, isentando o agente de pena. (Art. 22 do CP).`,ex:`Já na coação moral irresistível (uma grave ameaça, como "mate o caixa ou mato sua família"), a conduta existe, mas há exclusão da culpabilidade por inexigibilidade de conduta diversa, isentando o agente de pena.`,peg:`ameaça, como "mate o caixa ou mato sua família"), a conduta existe, mas há exclusão da culpabilidade por inexigibilidade de conduta diversa, isentando o agente de pena.`},
  {num:98,disc:`Penal`,title:`Desistência Voluntária x Arrependimento Eficaz`,kw:`DESISTÊNCIA VOLUNTÁRIA X ARREPENDIMENTO `,exp:`Ambos impedem a consumação e o agente só responde pelos atos já praticados. O macete para distinguir: na Desistência Voluntária, o agente inicia a execução, mas "deixa de fazer" (abandona a execução antes do fim). No Arrependimento Eficaz, o agente já realizou todos os atos executórios possíveis e "faz alguma coisa" ativamente para evitar que o resultado ocorra. (Art. 15 do CP).`,ex:`No Arrependimento Eficaz, o agente já realizou todos os atos executórios possíveis e "faz alguma coisa" ativamente para evitar que o resultado ocorra.`,peg:`distinguir: na Desistência Voluntária, o agente inicia a execução, mas "deixa de fazer" (abandona a execução antes do fim).`},
  {num:99,disc:`Penal`,title:`Arrependimento Posterior (O Limite Temporal)`,kw:`O LIMITE TEMPORAL`,exp:`Para reduzir a pena (de 1/3 a 2/3), o arrependimento posterior exige 3 condições inseparáveis: 1) o crime deve ter sido cometido sem violência ou grave ameaça; 2) o dano deve ser reparado (ou a coisa restituída) voluntariamente; e 3) o limite para fazer isso é até o recebimento da denúncia ou queixa. Não cabe em crime de roubo, por exemplo. (Art. 16 do CP).`,ex:`Não cabe em crime de roubo, por exemplo.`,peg:`ameaça; 2) o dano deve ser reparado (ou a coisa restituída) voluntariamente; e 3) o limite para fazer isso é até o recebimento da denúncia ou queixa.`},
  {num:100,disc:`Penal`,title:`Crime Impossível (Ou Crime Putativo)`,kw:`OU CRIME PUTATIVO`,exp:`Ocorre quando não se pune a tentativa. O grande macete é a palavra "Absoluta": a tentativa não é punida por ineficácia absoluta do meio (ex: arma de brinquedo) ou absoluta impropriedade do objeto (ex: atirar em um cadáver). Se a ineficácia ou impropriedade for apenas "relativa", configurará tentativa punível. (Art. 17 do CP).`,ex:`Se a ineficácia ou impropriedade for apenas "relativa", configurará tentativa punível.`,peg:`Ocorre quando não se pune a tentativa.`},
  {num:101,disc:`Penal`,title:`Regimes Prisionais (Reclusão x Detenção)`,kw:`RECLUSÃO X DETENÇÃO`,exp:`A diferença principal entre os dois tipos de pena restritiva de liberdade para o momento inicial da condenação. A pena de Reclusão admite o início do cumprimento em regime fechado, semiaberto ou aberto. Já a pena de Detenção deve iniciar obrigatoriamente no regime semiaberto ou aberto (não começa no fechado, salvo se houver regressão depois). (Art. 33, caput e § 2º do CP).`,ex:`Já a pena de Detenção deve iniciar obrigatoriamente no regime semiaberto ou aberto (não começa no fechado, salvo se houver regressão depois).`,peg:`A diferença principal entre os dois tipos de pena restritiva de liberdade para o momento inicial da condenação.`},
  {num:102,disc:`Penal`,title:`Substituição por Penas Restritivas de Direitos`,kw:`SUBSTITUIÇÃO POR PENAS RESTRITIVAS DE`,exp:`Se o crime for doloso, a substituição da prisão por PRD só é cabível se o crime for sem violência ou grave ameaça e a pena aplicada não for superior a 4 anos. No entanto, a FGV gosta da exceção: se o crime for culposo (sem intenção), a substituição é possível qualquer que seja a pena aplicada. (Art. 44, I, do CP).`,ex:`No entanto, a FGV gosta da exceção: se o crime for culposo (sem intenção), a substituição é possível qualquer que seja a pena aplicada.`,peg:`ameaça e a pena aplicada não for superior a 4 anos.`},
  {num:103,disc:`Penal`,title:`Concurso Formal (Próprio x Impróprio)`,kw:`PRÓPRIO X IMPRÓPRIO`,exp:`Quando o agente pratica vários crimes com uma só conduta, olhe para o dolo (intenção). Se não havia desígnios autônomos (não tinha intenção de todos os crimes), adota-se o Concurso Formal Próprio, com a regra da exasperação (pega a pena mais grave e aumenta). Se, mediante uma única conduta, o agente teve intenção (dolo) para produzir todos os resultados simultaneamente, o concurso é Impróprio e aplica-se o cúmulo material (soma-se todas as penas). (Art. 70 do CP).`,ex:`Se, mediante uma única conduta, o agente teve intenção (dolo) para produzir todos os resultados simultaneamente, o concurso é Impróprio e aplica-se o cúmulo material (soma-se todas as penas).`,peg:`Quando o agente pratica vários crimes com uma só conduta, olhe para o dolo (intenção).`},
  {num:104,disc:`Penal`,title:`Prescrição de Crimes contra Vulneráveis`,kw:`PRESCRIÇÃO DE CRIMES CONTRA VULNERÁVEIS`,exp:`Este é um macete essencial sobre contagem de tempo (Art. 111, V). Em crimes contra a dignidade sexual ou que envolvam violência contra crianças e adolescentes, o prazo de prescrição não começa no dia do crime. O prazo só começa a correr da data em que a vítima completar 18 (dezoito) anos, exceto se a ação penal já tiver sido proposta antes. (Art. 111, V do CP).`,ex:`O prazo só começa a correr da data em que a vítima completar 18 (dezoito) anos, exceto se a ação penal já tiver sido proposta antes.`,peg:`Este é um macete essencial sobre contagem de tempo (Art.`},
  {num:105,disc:`Penal`,title:`O Perdão Judicial e o Homicídio`,kw:`O PERDÃO JUDICIAL E O`,exp:`O perdão judicial é uma causa de extinção da punibilidade aplicada pelo juiz em casos onde o sofrimento do próprio agente torna a pena desnecessária. Lembre-se firmemente: no homicídio, o perdão judicial só é admitido na modalidade culposa (ex: pai atropela o próprio filho sem intenção). Não existe perdão judicial para homicídio doloso. (Art. 121, § 5º do CP).`,ex:`Não existe perdão judicial para homicídio doloso.`,peg:`firmemente: no homicídio, o perdão judicial só é admitido na modalidade culposa (ex: pai atropela o próprio filho sem intenção).`},
  {num:106,disc:`Penal`,title:`Estelionato x Furto mediante Fraude`,kw:`ESTELIONATO X FURTO MEDIANTE FRAUDE`,exp:`Duas condutas que envolvem o engano, mas com atuações totalmente diferentes da vítima. No Furto mediante fraude, o agente usa a fraude para diminuir a vigilância da vítima e é o próprio bandido quem subtrai (pega) o bem. No Estelionato, a vítima, sendo induzida a erro pela fraude, entrega voluntariamente a coisa ao criminoso. (Art. 155, §4º, II e Art. 171 do CP).`,ex:`No Estelionato, a vítima, sendo induzida a erro pela fraude, entrega voluntariamente a coisa ao criminoso.`,peg:`Duas condutas que envolvem o engano, mas com atuações totalmente diferentes da vítima.`},
  {num:107,disc:`Penal`,title:`Consumação do Roubo e do Furto (Súmula 582 do STJ)`,kw:`SÚMULA 582 DO STJ`,exp:`Os tribunais adotam a Teoria da Amotio (ou Apprehensio). O crime de furto ou roubo se consuma no exato momento da inversão da posse da coisa, ainda que seja por um breve momento e mesmo que ocorra perseguição policial imediata que recupere o bem. É expressamente dispensável que o criminoso tenha a posse mansa, pacífica ou desvigiada do bem.`,ex:`É expressamente dispensável que o criminoso tenha a posse mansa, pacífica ou desvigiada do bem.`,peg:`Os tribunais adotam a Teoria da Amotio (ou Apprehensio).`},
  {num:108,disc:`Penal`,title:`Peculato Culposo e a Mágica da Reparação`,kw:`PECULATO CULPOSO E A MÁGICA`,exp:`Ocorre quando a negligência do servidor facilita o crime doloso de outra pessoa contra a Administração. Há um efeito temporal fortíssimo que é amado pelas bancas: se o funcionário reparar o dano antes da sentença irrecorrível, a punibilidade é extinta. Se ele reparar o dano depois da sentença, a consequência muda: a pena é apenas reduzida pela metade. (Art. 312, § 2º e § 3º do CP).`,ex:`Se ele reparar o dano depois da sentença, a consequência muda: a pena é apenas reduzida pela metade.`,peg:`Ocorre quando a negligência do servidor facilita o crime doloso de outra pessoa contra a Administração.`},
  {num:109,disc:`Penal`,title:`Concussão x Corrupção Passiva (O Macete dos Verbos)`,kw:`O MACETE DOS VERBOS`,exp:`Ambos são crimes praticados por funcionário público, mas os verbos-núcleo decidem a questão. Na Concussão, o funcionário impõe, o verbo é EXIGIR (vantagem indevida). Na Corrupção Passiva, o funcionário não impõe, os verbos são SOLICITAR, RECEBER ou ACEITAR promessa (de vantagem indevida). (Art. 316 e 317 do CP). PROCESSO PENAL 16 Macetes para Gabaritar Direito Processual Penal na OAB`,ex:`PROCESSO PENAL 16 Macetes para Gabaritar Direito Processual Penal na OAB.`,peg:`Ambos são crimes praticados por funcionário público, mas os verbos-núcleo decidem a questão.`},
  {num:110,disc:`Processo Penal`,title:`O Limite do Advogado no Inquérito Policial`,kw:`O LIMITE DO ADVOGADO NO`,exp:`O inquérito é inquisitivo, mas o advogado tem o direito de assistir seu cliente investigado durante os depoimentos, sob pena de nulidade. Contudo, o advogado NÃO tem o direito de acompanhar as oitivas de outras pessoas, como testemunhas ou vítimas (Lei 8.906/94, Art. 7º, XXI e Petição 7612 do STF).`,ex:`7º, XXI e Petição 7612 do STF).`,peg:`O inquérito é inquisitivo, mas o advogado tem o direito de assistir seu cliente investigado durante os depoimentos, sob pena de nulidade.`},
  {num:111,disc:`Processo Penal`,title:`A Pegadinha da Súmula Vinculante 14`,kw:`A PEGADINHA DA SÚMULA VINCULANTE`,exp:`O sigilo do Inquérito Policial (IP) não se estende ao advogado, que tem amplo acesso aos autos. O macete é: esse acesso é apenas para as provas já documentadas. O delegado não é obrigado a mostrar diligências que ainda estão em andamento. Além disso, se o IP estiver sob sigilo judicial, é obrigatória a apresentação de procuração (Súmula Vinculante 14 do STF).`,ex:`Além disso, se o IP estiver sob sigilo judicial, é obrigatória a apresentação de procuração (Súmula Vinculante 14 do STF).`,peg:`esse acesso é apenas para as provas já documentadas.`},
  {num:112,disc:`Processo Penal`,title:`Arquivamento e Desarquivamento do IP`,kw:`ARQUIVAMENTO E DESARQUIVAMENTO DO IP`,exp:`A autoridade policial (Delegado) jamais poderá mandar arquivar os autos de inquérito (Art. 17 do CPP). Uma vez arquivado pelo juiz, a requerimento do promotor, o desarquivamento e a ação penal só poderão ser iniciados se surgirem novas provas (Súmula 524 do STF).`,ex:`Uma vez arquivado pelo juiz, a requerimento do promotor, o desarquivamento e a ação penal só poderão ser iniciados se surgirem novas provas (Súmula 524 do STF).`,peg:`A autoridade policial (Delegado) jamais poderá mandar arquivar os autos de inquérito (Art.`},
  {num:113,disc:`Processo Penal`,title:`Coisa Julgada Material no Inquérito Policial`,kw:`COISA JULGADA MATERIAL NO INQUÉRITO`,exp:`Em regra, o arquivamento do IP faz apenas coisa julgada formal, permitindo reabertura. Porém, se o arquivamento ocorrer por atipicidade da conduta (o fato não é crime) ou por extinção da punibilidade (ex: morte, prescrição), ele fará coisa julgada material, impedindo a reabertura do caso mesmo que surjam novas provas!.`,ex:`Porém, se o arquivamento ocorrer por atipicidade da conduta (o fato não é crime) ou por extinção da punibilidade (ex: morte, prescrição), ele fará coisa julgada material, impedindo a reabertura do caso mesmo que surjam novas provas.`,peg:`Em regra, o arquivamento do IP faz apenas coisa julgada formal, permitindo reabertura.`},
  {num:114,disc:`Processo Penal`,title:`O Limite da Retratação da Vítima`,kw:`O LIMITE DA RETRATAÇÃO DA`,exp:`Na ação penal pública condicionada, a representação da vítima é a condição de procedibilidade para o MP atuar. O macete temporal é clássico: a retratação (desistência) da representação só pode ocorrer até o oferecimento da denúncia. Depois de oferecida a denúncia, a representação torna-se irretratável (Art. 25 do CPP).`,ex:`Depois de oferecida a denúncia, a representação torna-se irretratável (Art.`,peg:`Na ação penal pública condicionada, a representação da vítima é a condição de procedibilidade para o MP atuar.`},
  {num:115,disc:`Processo Penal`,title:`Condenação com Base Exclusiva no Inquérito? NUNCA!`,kw:`CONDENAÇÃO COM BASE EXCLUSIVA NO`,exp:`O juiz formará sua convicção pela livre apreciação da prova produzida em contraditório judicial. Elementos de informação colhidos na fase de inquérito não podem, por si sós, fundamentar uma condenação. A única exceção a essa regra é para as provas cautelares, não repetíveis e antecipadas (Art. 155 do CPP).`,ex:`A única exceção a essa regra é para as provas cautelares, não repetíveis e antecipadas (Art.`,peg:`O juiz formará sua convicção pela livre apreciação da prova produzida em contraditório judicial.`},
  {num:116,disc:`Processo Penal`,title:`A Confissão e o Exame de Corpo de Delito`,kw:`A CONFISSÃO E O EXAME`,exp:`Para os crimes que deixam vestígios (não transeuntes), a realização do exame de corpo de delito (direto ou indireto) é indispensável. Memorize para a prova: a confissão do acusado NÃO supre a falta do exame pericial.`,ex:`Memorize para a prova: a confissão do acusado NÃO supre a falta do exame pericial.`,peg:`Para os crimes que deixam vestígios (não transeuntes), a realização do exame de corpo de delito (direto ou indireto) é indispensável.`},
  {num:117,disc:`Processo Penal`,title:`O Horário da Busca e Apreensão Domiciliar`,kw:`O HORÁRIO DA BUSCA E`,exp:`A casa é asilo inviolável. Sem mandado judicial, a entrada é permitida a qualquer hora em caso de flagrante delito, desastre, para prestar socorro ou com consentimento do morador. Com mandado judicial, o cumprimento só pode ocorrer durante o dia (das 5h às 21h), conforme dita a Lei de Abuso de Autoridade.`,ex:`Com mandado judicial, o cumprimento só pode ocorrer durante o dia (das 5h às 21h), conforme dita a Lei de Abuso de Autoridade.`,peg:`Sem mandado judicial, a entrada é permitida a qualquer hora em caso de flagrante delito, desastre, para prestar socorro ou com consentimento do morador.`},
  {num:118,disc:`Processo Penal`,title:`Flagrante Preparado (Crime Impossível)`,kw:`CRIME IMPOSSÍVEL`,exp:`Quando a polícia ou um terceiro induz ou estimula a prática de um crime com o objetivo de prender o autor em flagrante, trata-se de flagrante preparado/provocado. A consequência é que não há crime, pois a preparação torna impossível a sua consumação (Súmula 145 do STF).`,ex:`A consequência é que não há crime, pois a preparação torna impossível a sua consumação (Súmula 145 do STF).`,peg:`Quando a polícia ou um terceiro induz ou estimula a prática de um crime com o objetivo de prender o autor em flagrante, trata-se de flagrante preparado/provocado.`},
  {num:119,disc:`Processo Penal`,title:`Prisão Temporária x Preventiva (Fase e Prazo)`,kw:`FASE E PRAZO`,exp:`A Prisão Temporária é exclusiva da fase do inquérito policial e possui prazo determinado (5 dias prorrogáveis por mais 5; ou 30+30 dias para crimes hediondos). Já a Prisão Preventiva não tem prazo determinado e pode ser decretada em qualquer fase (investigação ou processo penal). Fique atento: Nenhuma das duas pode ser decretada de ofício pelo juiz! (Lei 7.960/89 e Art. 312 do CPP).`,ex:`Fique atento: Nenhuma das duas pode ser decretada de ofício pelo juiz.`,peg:`Nenhuma das duas pode ser decretada de ofício pelo juiz! (Lei 7.`},
  {num:120,disc:`Processo Penal`,title:`A Regra Atual do Foro por Prerrogativa de Função`,kw:`A REGRA ATUAL DO FORO`,exp:`O foro privilegiado julgado pelo STF não é automático para tudo. Ele se aplica apenas aos crimes cometidos durante o exercício do cargo E que estejam relacionados às funções desempenhadas. Outro detalhe: após o término da instrução processual, a competência não muda mais, mesmo que a pessoa saia do cargo (STF, Ação Penal 937).`,ex:`Outro detalhe: após o término da instrução processual, a competência não muda mais, mesmo que a pessoa saia do cargo (STF, Ação Penal 937).`,peg:`O foro privilegiado julgado pelo STF não é automático para tudo.`},
  {num:121,disc:`Processo Penal`,title:`O Fim da 1ª Fase do Tribunal do Júri`,kw:`O FIM DA 1ª FASE`,exp:`O Júri é um procedimento bifásico. A primeira fase (Juízo de Acusação) se encerra com uma de quatro decisões possíveis: Pronúncia (manda para o júri); Impronúncia (falta de provas de autoria ou materialidade); Absolvição Sumária (provada a inexistência do fato ou que o réu não é autor); ou Desclassificação (o crime não é doloso contra a vida) (Arts. 413, 414, 415 e 419 do CPP).`,ex:`413, 414, 415 e 419 do CPP).`,peg:`O Júri é um procedimento bifásico.`},
  {num:122,disc:`Processo Penal`,title:`Desaforamento no Tribunal do Júri`,kw:`DESAFORAMENTO NO TRIBUNAL DO JÚRI`,exp:`Trata-se da transferência do julgamento do Júri para outra comarca. Pode ocorrer por interesse da ordem pública, dúvida sobre a imparcialidade do júri ou segurança pessoal do acusado. Além disso, pode ser pedido se o julgamento não acontecer no prazo de 6 meses após o trânsito em julgado da pronúncia por excesso de serviço (Arts. 427 e 428 do CPP).`,ex:`Além disso, pode ser pedido se o julgamento não acontecer no prazo de 6 meses após o trânsito em julgado da pronúncia por excesso de serviço (Arts.`,peg:`Trata-se da transferência do julgamento do Júri para outra comarca.`},
  {num:123,disc:`Processo Penal`,title:`As Vedações nos Debates do Júri`,kw:`AS VEDAÇÕES NOS DEBATES DO`,exp:`Sob pena de nulidade, a acusação e a defesa não podem usar certos argumentos em plenário. É terminantemente proibido referir-se à decisão de pronúncia (ou uso de algemas) como argumento de autoridade que beneficie/prejudique o réu, e não se pode usar o silêncio do acusado em seu desfavor (Art. 478 do CPP).`,ex:`É terminantemente proibido referir-se à decisão de pronúncia (ou uso de algemas) como argumento de autoridade que beneficie/prejudique o réu, e não se pode usar o silêncio do acusado em seu desfavor (Art.`,peg:`Sob pena de nulidade, a acusação e a defesa não podem usar certos argumentos em plenário.`},
  {num:124,disc:`Processo Penal`,title:`O Efeito Suspensivo Excepcional do RESE`,kw:`O EFEITO SUSPENSIVO EXCEPCIONAL DO`,exp:`A regra do Recurso em Sentido Estrito (RESE) é que ele não tem efeito suspensivo. A exceção de ouro que mais cai na OAB é: o recurso contra a decisão de pronúncia (que envia o réu ao Júri) suspenderá o julgamento (Art. 581, IV do CPP).`,ex:`A exceção de ouro que mais cai na OAB é: o recurso contra a decisão de pronúncia (que envia o réu ao Júri) suspenderá o julgamento (Art.`,peg:`A regra do Recurso em Sentido Estrito (RESE) é que ele não tem efeito suspensivo.`},
  {num:125,disc:`Processo Penal`,title:`Apelação no Júri (Decisão Manifestamente Contrária às Provas)`,kw:`APELAÇÃO NO JÚRI DECISÃO MANIFESTAMENTE`,exp:`Se a decisão dos jurados for "manifestamente contrária à prova dos autos", a parte pode apelar. Se o Tribunal der provimento, ele não condena nem absolve, ele anula o julgamento e submete o réu a um novo júri. O macete supremo: não se admite uma segunda apelação pelo mesmo motivo (Art. 593 do CPP). DIREITO DO TRABALHO`,ex:`O macete supremo: não se admite uma segunda apelação pelo mesmo motivo (Art.`,peg:`Se a decisão dos jurados for "manifestamente contrária à prova dos autos", a parte pode apelar.`},
  {num:126,disc:`Direito do Trabalho`,title:`Horas in itinere (Tempo de Trajeto)`,kw:`TRAJETO NÃO CONTA NA JORNADA`,exp:`O tempo que o empregado leva de sua residência até o local de trabalho e vice-versa não é computado na jornada de trabalho. Isso se aplica mesmo nas situações em que o próprio empregador forneça o transporte, sendo um tema clássico pós-Reforma Trabalhista. (Art. 58, § 2º da CLT).`,ex:`Empresa fornece ônibus: tempo de trajeto não gera horas extras.`,peg:`Incluir tempo de trajeto na jornada.`},
  {num:127,disc:`Direito do Trabalho`,title:`Tempo à Disposição (As Exceções)`,kw:`AS EXCEÇÕES`,exp:`O tempo em que o empregado permanece na empresa, por escolha própria, para atividades particulares não é considerado tempo à disposição do empregador. Logo, não gera direito a horas extras o tempo gasto com práticas religiosas, lazer, estudo, higiene pessoal ou troca de uniforme (quando esta não for obrigatória na empresa). (Art. 4º, § 2º da CLT).`,ex:`Logo, não gera direito a horas extras o tempo gasto com práticas religiosas, lazer, estudo, higiene pessoal ou troca de uniforme (quando esta não for obrigatória na empresa).`,peg:`O tempo em que o empregado permanece na empresa, por escolha própria, para atividades particulares não é considerado tempo à disposição do empregador.`},
  {num:128,disc:`Direito do Trabalho`,title:`A Natureza do Intervalo Intrajornada Suprimido`,kw:`A NATUREZA DO INTERVALO INTRAJORNADA`,exp:`A não concessão ou a concessão parcial do intervalo intrajornada acarreta o pagamento apenas do período efetivamente suprimido com um acréscimo de 50%. Lembre-se que essa verba tem natureza indenizatória, o que significa que não gera reflexos em outras parcelas salariais do contrato. (Art. 71, § 4º da CLT).`,ex:`Lembre-se que essa verba tem natureza indenizatória, o que significa que não gera reflexos em outras parcelas salariais do contrato.`,peg:`que essa verba tem natureza indenizatória, o que significa que não gera reflexos em outras parcelas salariais do contrato.`},
  {num:129,disc:`Direito do Trabalho`,title:`Jornada 12x36 e os Feriados`,kw:`JORNADA 12X36 E OS FERIADOS`,exp:`Na jornada de 12 horas de trabalho por 36 horas de descanso, a remuneração mensal pactuada já abrange o pagamento do descanso semanal remunerado (DSR) e dos feriados. As prorrogações de trabalho noturno (após as 5h) e o trabalho em feriados já são considerados compensados por esse regime. (Art. 59A, Parágrafo único da CLT).`,ex:`59A, Parágrafo único da CLT).`,peg:`Na jornada de 12 horas de trabalho por 36 horas de descanso, a remuneração mensal pactuada já abrange o pagamento do descanso semanal remunerado (DSR) e dos feriados.`},
  {num:130,disc:`Direito do Trabalho`,title:`Teletrabalho e o Controle de Jornada`,kw:`TELETRABALHO E O CONTROLE DE`,exp:`Nem todo teletrabalho exclui o direito a horas extras. A exceção ao controle de jornada (que retira o direito a horas extras) aplicase apenas ao teletrabalho remunerado por produção ou tarefa. O teletrabalho por jornada de tempo normal está sujeito ao controle de horário. (Art. 62, III, e Art. 75-B, § 2º da CLT).`,ex:`O teletrabalho por jornada de tempo normal está sujeito ao controle de horário.`,peg:`Nem todo teletrabalho exclui o direito a horas extras.`},
  {num:131,disc:`Direito do Trabalho`,title:`Férias x Faltas Injustificadas`,kw:`FÉRIAS X FALTAS INJUSTIFICADAS`,exp:`O empregador é expressamente proibido de descontar diretamente as faltas do empregado dos seus dias de férias. O que acontece é a redução do período de gozo conforme a tabela da CLT. Por exemplo, se o empregado tiver até 5 faltas injustificadas, mantém os 30 dias corridos; de 6 a 14 faltas, cai para 24 dias corridos de férias. (Art. 130 e § 1º da CLT).`,ex:`Por exemplo, se o empregado tiver até 5 faltas injustificadas, mantém os 30 dias corridos; de 6 a 14 faltas, cai para 24 dias corridos de férias.`,peg:`O empregador é expressamente proibido de descontar diretamente as faltas do empregado dos seus dias de férias.`},
  {num:132,disc:`Direito do Trabalho`,title:`Férias Coletivas (A regra para os "novatos")`,kw:`A REGRA PARA OS "NOVATOS"`,exp:`Empregados com menos de 12 meses de contrato têm direito a gozar férias coletivas proporcionais ao tempo de serviço. O grande macete de prova é que, após o retorno dessas férias proporcionais, o período aquisitivo anterior é zerado e inicia-se um novo período aquisitivo de 12 meses para aquele trabalhador. (Art. 140 da CLT).`,ex:`O grande macete de prova é que, após o retorno dessas férias proporcionais, o período aquisitivo anterior é zerado e inicia-se um novo período aquisitivo de 12 meses para aquele trabalhador.`,peg:`Empregados com menos de 12 meses de contrato têm direito a gozar férias coletivas proporcionais ao tempo de serviço.`},
  {num:133,disc:`Direito do Trabalho`,title:`Trabalho Noturno (Mulher x Menor)`,kw:`MULHER X MENOR`,exp:`A mulher tem direito ao adicional noturno de no mínimo 20% e à hora noturna reduzida (52min30s) sob as mesmas regras gerais. Porém, grave para a prova: ao menor de 18 anos é totalmente proibido o trabalho noturno, considerado aquele executado entre as 22h e as 5h. (Arts. 73, 381 e 404 da CLT).`,ex:`Porém, grave para a prova: ao menor de 18 anos é totalmente proibido o trabalho noturno, considerado aquele executado entre as 22h e as 5h.`,peg:`para a prova: ao menor de 18 anos é totalmente proibido o trabalho noturno, considerado aquele executado entre as 22h e as 5h.`},
  {num:134,disc:`Direito do Trabalho`,title:`Afastamento de Atividades Insalubres (Gestantes e Lactantes)`,kw:`GESTANTES E LACTANTES`,exp:`A gestante deve ser afastada automaticamente de atividades consideradas insalubres em grau máximo. No entanto, em caso de insalubridade de graus médio ou mínimo (para gestantes) ou de qualquer grau (para lactantes), o afastamento só será obrigatório mediante a apresentação de atestado de saúde emitido por médico de confiança da mulher. (Art. 394-A da CLT).`,ex:`No entanto, em caso de insalubridade de graus médio ou mínimo (para gestantes) ou de qualquer grau (para lactantes), o afastamento só será obrigatório mediante a apresentação de atestado de saúde emitido por médico de confiança da mulher.`,peg:`A gestante deve ser afastada automaticamente de atividades consideradas insalubres em grau máximo.`},
  {num:135,disc:`Direito do Trabalho`,title:`Limite de Força Muscular`,kw:`LIMITE DE FORÇA MUSCULAR`,exp:`As regras para o emprego de força física são rigorosamente idênticas para o trabalho da mulher e o trabalho do menor. É vedado o trabalho que demande força muscular contínua superior a 20 quilos ou força ocasional superior a 25 quilos. (Arts. 390 e 405, § 5º da CLT).`,ex:`É vedado o trabalho que demande força muscular contínua superior a 20 quilos ou força ocasional superior a 25 quilos.`,peg:`As regras para o emprego de força física são rigorosamente idênticas para o trabalho da mulher e o trabalho do menor.`},
  {num:136,disc:`Direito do Trabalho`,title:`O Grupo Econômico e os Sócios`,kw:`O GRUPO ECONÔMICO E OS`,exp:`A mera identidade de sócios entre empresas não é suficiente para caracterizar o grupo econômico. Para que o grupo exista e gere a responsabilidade solidária pelas obrigações trabalhistas, a lei exige a demonstração de interesse integrado, efetiva comunhão de interesses e atuação conjunta das empresas. (Art. 2º, § 3º da CLT).`,ex:`Para que o grupo exista e gere a responsabilidade solidária pelas obrigações trabalhistas, a lei exige a demonstração de interesse integrado, efetiva comunhão de interesses e atuação conjunta das empresas.`,peg:`A mera identidade de sócios entre empresas não é suficiente para caracterizar o grupo econômico.`},
  {num:137,disc:`Direito do Trabalho`,title:`Remuneração x Salário (O rol do que NÃO integra)`,kw:`O ROL DO QUE NÃO INTEGRA`,exp:`O salário é fixo (mais comissões/gratificações), e a remuneração é a soma do salário mais as gorjetas. Fique muito atento: parcelas como ajudas de custo, auxílio-alimentação, diárias para viagem, prêmios e abonos NÃO integram a remuneração, não se incorporam ao contrato e não geram reflexos, mesmo que pagas com habitualidade. (Art. 457, § 2º da CLT).`,ex:`Fique muito atento: parcelas como ajudas de custo, auxílio-alimentação, diárias para viagem, prêmios e abonos NÃO integram a remuneração, não se incorporam ao contrato e não geram reflexos, mesmo que pagas com habitualidade.`,peg:`O salário é fixo (mais comissões/gratificações), e a remuneração é a soma do salário mais as gorjetas.`},
  {num:138,disc:`Direito do Trabalho`,title:`Estabilidade do Dirigente Sindical`,kw:`ESTABILIDADE DO DIRIGENTE SINDICAL`,exp:`A garantia provisória de emprego inicia-se no registro da candidatura e vai até 1 (um) ano após o final do mandato, caso o empregado seja eleito (inclusive como suplente). A pegadinha na prova: para a estabilidade valer, a entidade sindical tem o dever obrigatório de comunicar a empresa, por escrito, em 24 horas, sobre o registro e a posse. (Art. 543, §§ 3º e 5º da CLT).`,ex:`A pegadinha na prova: para a estabilidade valer, a entidade sindical tem o dever obrigatório de comunicar a empresa, por escrito, em 24 horas, sobre o registro e a posse.`,peg:`A garantia provisória de emprego inicia-se no registro da candidatura e vai até 1 (um) ano após o final do mandato, caso o empregado seja eleito (inclusive como suplente).`},
  {num:139,disc:`Direito do Trabalho`,title:`Negociado sobre Legislado (CCT e ACT)`,kw:`CCT E ACT`,exp:`Acordos e Convenções Coletivas prevalecem sobre a lei em matérias como a criação de banco de horas anual ou a redução do intervalo intrajornada (desde que respeitado o limite mínimo de 30 minutos). No entanto, é considerado objeto ilícito negociar a supressão ou redução de direitos fundamentais, tais como FGTS, Salário Mínimo, Licença-Maternidade de 120 dias, repouso semanal e aviso prévio. (Arts. 611-A e 611-B da CLT). PROCESSO DO TRABALHO`,ex:`No entanto, é considerado objeto ilícito negociar a supressão ou redução de direitos fundamentais, tais como FGTS, Salário Mínimo, Licença-Maternidade de 120 dias, repouso semanal e aviso prévio.`,peg:`Acordos e Convenções Coletivas prevalecem sobre a lei em matérias como a criação de banco de horas anual ou a redução do intervalo intrajornada (desde que respeitado o limite mínimo de 30 minutos).`},
  {num:140,disc:`Processo do Trabalho`,title:`Aplicação Subsidiária do CPC (Os dois requisitos)`,kw:`OS DOIS REQUISITOS`,exp:`O Código de Processo Civil só pode ser aplicado subsidiariamente ao Processo do Trabalho se dois requisitos cumulativos forem preenchidos: omissão na CLT e compatibilidade com os princípios do processo trabalhista, como celeridade e proteção ao hipossuficiente (Art. 769 da CLT).`,ex:`O Código de Processo Civil só pode ser aplicado subsidiariamente ao Processo do Trabalho se dois requisitos cumulativos forem preenchidos: omissão na `,peg:`O Código de Processo Civil só pode ser aplicado subsidiariamente ao Processo do Trabalho se dois requisitos cumulativos forem preenchidos: omissão na CLT e compatibilidade com os princípios do processo trabalhista, como celeridade e proteção ao hipos`},
  {num:141,disc:`Processo do Trabalho`,title:`Contagem de Prazos Trabalhistas (Dias Úteis e Suspensão)`,kw:`DIAS ÚTEIS E SUSPENSÃO`,exp:`Após a Reforma Trabalhista, a contagem de prazos passou a ser feita exclusivamente em dias úteis, excluindo o dia do começo e incluindo o dia do vencimento. Lembre-se também do "recesso": os prazos ficam suspensos entre 20 de dezembro e 20 de janeiro (Art. 775 e 775-A da CLT).`,ex:`Lembre-se também do "recesso": os prazos ficam suspensos entre 20 de dezembro e 20 de janeiro (Art.`,peg:`também do "recesso": os prazos ficam suspensos entre 20 de dezembro e 20 de janeiro (Art.`},
  {num:142,disc:`Processo do Trabalho`,title:`Custas Processuais (O Teto e o Piso)`,kw:`O TETO E O PISO`,exp:`As custas no processo de conhecimento são de 2%, sendo pagas pelo vencido ao final. Grave os limites para a OAB: o valor mínimo (piso) é de R$ 10,64 e o limite máximo (teto) é de quatro vezes o teto dos benefícios do RGPS (INSS) (Art. 789 da CLT).`,ex:`Grave os limites para a OAB: o valor mínimo (piso) é de R$ 10,64 e o limite máximo (teto) é de quatro vezes o teto dos benefícios do RGPS (INSS) (Art.`,peg:`os limites para a OAB: o valor mínimo (piso) é de R$ 10,64 e o limite máximo (teto) é de quatro vezes o teto dos benefícios do RGPS (INSS) (Art.`},
  {num:143,disc:`Processo do Trabalho`,title:`Honorários de Sucumbência e Reconvenção`,kw:`HONORÁRIOS DE SUCUMBÊNCIA E RECONVENÇÃO`,exp:`São fixados entre 5% e 15% sobre o valor da liquidação, proveito econômico ou valor da causa. O macete para não escorregar: a CLT prevê expressamente que também são devidos honorários de sucumbência na reconvenção (Art. 791-A, § 5º da CLT).`,ex:`O macete para não escorregar: a CLT prevê expressamente que também são devidos honorários de sucumbência na reconvenção (Art.`,peg:`não escorregar: a CLT prevê expressamente que também são devidos honorários de sucumbência na reconvenção (Art.`},
  {num:144,disc:`Processo do Trabalho`,title:`A Dupla Punição pela Ausência do Reclamante`,kw:`A DUPLA PUNIÇÃO PELA AUSÊNCIA`,exp:`Se o reclamante faltar injustificadamente à audiência inicial, a ação é arquivada e ele é condenado ao pagamento das custas, mesmo se for beneficiário da justiça gratuita! Ele só escapa da multa se comprovar motivo legal em 15 dias, sendo o pagamento requisito para ajuizar nova ação (Art. 844, §§ 2º e 3º da CLT).`,ex:`Ele só escapa da multa se comprovar motivo legal em 15 dias, sendo o pagamento requisito para ajuizar nova ação (Art.`,peg:`Se o reclamante faltar injustificadamente à audiência inicial, a ação é arquivada e ele é condenado ao pagamento das custas, mesmo se for beneficiário da justiça gratuita.`},
  {num:145,disc:`Processo do Trabalho`,title:`Preposto não precisa ser empregado`,kw:`PREPOSTO NÃO PRECISA SER EMPREGADO`,exp:`O empregador pode se fazer substituir por um gerente ou preposto na audiência. A grande pegadinha da FGV é sugerir o contrário, mas a regra é clara: o preposto não precisa ser empregado da reclamada para representá-la validamente (Art. 843, § 3º da CLT).`,ex:`A grande pegadinha da FGV é sugerir o contrário, mas a regra é clara: o preposto não precisa ser empregado da reclamada para representá-la validamente (Art.`,peg:`O empregador pode se fazer substituir por um gerente ou preposto na audiência.`},
  {num:146,disc:`Processo do Trabalho`,title:`Rito Sumaríssimo (A regra do Edital e do Valor)`,kw:`A REGRA DO EDITAL E DO VALOR`,exp:`Cabível para causas de até 40 salários mínimos. Grave duas restrições absolutas deste rito: a Administração Pública (direta, autárquica e fundacional) não pode ser parte, e não se admite citação por edital de forma alguma (Art. 852-A, Parágrafo único e 852-B, II da CLT).`,ex:`852-A, Parágrafo único e 852-B, II da CLT).`,peg:`duas restrições absolutas deste rito: a Administração Pública (direta, autárquica e fundacional) não pode ser parte, e não se admite citação por edital de forma alguma (Art.`},
  {num:147,disc:`Processo do Trabalho`,title:`O Macete dos Números de Testemunhas (3 - 2 - 6)`,kw:`3 - 2 - 6`,exp:`A quantidade máxima de testemunhas varia pelo rito. No Procedimento Ordinário: até 3 para cada parte. No Procedimento Sumaríssimo: até 2 para cada parte. No Inquérito para Apuração de Falta Grave: até 6 para cada parte (Arts. 821 e 852-H, § 2º da CLT).`,ex:`No Inquérito para Apuração de Falta Grave: até 6 para cada parte (Arts.`,peg:`até 6 para cada parte (Arts.`},
  {num:148,disc:`Processo do Trabalho`,title:`Homologação de Acordo Extrajudicial (Advogados Diferentes)`,kw:`ADVOGADOS DIFERENTES`,exp:`Neste procedimento de jurisdição voluntária, exige-se petição inicial conjunta. O detalhe letal para a prova: é expressamente proibido que as partes sejam representadas pelo mesmo advogado. Cada um deve ter o seu próprio (Art. 855-B, § 1º da CLT).`,ex:`Cada um deve ter o seu próprio (Art.`,peg:`Neste procedimento de jurisdição voluntária, exige-se petição inicial conjunta.`},
  {num:149,disc:`Processo do Trabalho`,title:`Efeito do Acordo Extrajudicial na Prescrição e na Multa`,kw:`EFEITO DO ACORDO EXTRAJUDICIAL NA`,exp:`Distribuir o pedido de homologação de acordo suspende o prazo prescricional para os direitos nele especificados. Contudo, essa petição não suspende o prazo de 10 dias para o pagamento das verbas rescisórias. Se a empresa atrasar, sofrerá a multa do Art. 477, § 8º (Arts. 855-C e 855-E da CLT).`,ex:`Se a empresa atrasar, sofrerá a multa do Art.`,peg:`Distribuir o pedido de homologação de acordo suspende o prazo prescricional para os direitos nele especificados.`},
  {num:150,disc:`Processo do Trabalho`,title:`O Fim do Impulso Oficial na Execução`,kw:`O FIM DO IMPULSO OFICIAL`,exp:`A execução trabalhista não é mais iniciada automaticamente pelo juiz na maioria dos casos. O macete é: a execução deve ser promovida pelas partes, e o juiz só poderá iniciá-la de ofício se a parte não estiver representada por advogado (jus postulandi) (Art. 878 da CLT).`,ex:`O macete é: a execução deve ser promovida pelas partes, e o juiz só poderá iniciá-la de ofício se a parte não estiver representada por advogado (jus postulandi) (Art.`,peg:`a execução deve ser promovida pelas partes, e o juiz só poderá iniciá-la de ofício se a parte não estiver representada por advogado (jus postulandi) (Art.`},
  {num:151,disc:`Processo do Trabalho`,title:`Prazos da Execução (Os 48h e os 5 dias)`,kw:`OS 48H E OS 5 DIAS`,exp:`Após citado na execução, o executado tem um prazo curtíssimo de 48 horas para pagar a dívida ou garantir o juízo. Somente após garantido o juízo (com depósito, seguro ou penhora), ele ganha o prazo de 5 dias para opor Embargos à Execução (Arts. 880 e 884 da CLT).`,ex:`Somente após garantido o juízo (com depósito, seguro ou penhora), ele ganha o prazo de 5 dias para opor Embargos à Execução (Arts.`,peg:`Após citado na execução, o executado tem um prazo curtíssimo de 48 horas para pagar a dívida ou garantir o juízo.`},
  {num:152,disc:`Processo do Trabalho`,title:`Irrecorribilidade das Interlocutórias`,kw:`IRRECORRIBILIDADE DAS INTERLOCUTÓRIAS`,exp:`Na Justiça do Trabalho vigora o princípio da irrecorribilidade imediata das decisões interlocutórias (aquelas que resolvem incidentes, mas não encerram o processo). O prejudicado não pode recorrer na hora; deve aguardar a decisão definitiva para só então impugná-la (Art. 893, § 1º da CLT).`,ex:`O prejudicado não pode recorrer na hora; deve aguardar a decisão definitiva para só então impugná-la (Art.`,peg:`Na Justiça do Trabalho vigora o princípio da irrecorribilidade imediata das decisões interlocutórias (aquelas que resolvem incidentes, mas não encerram o processo).`},
  {num:153,disc:`Processo do Trabalho`,title:`A Regra do "Prazo 8" e a Exceção do "5" (Recursos)`,kw:`RECURSOS`,exp:`Para não se confundir nos prazos recursais trabalhistas, lembre-se que quase tudo é no prazo de 8 dias (Recurso Ordinário, Recurso de Revista, Agravo de Petição, Agravo de Instrumento e Embargos no TST). A única grande exceção são os Embargos de Declaração, que devem ser opostos no prazo de 5 dias (Arts. 897-A e 900 da CLT). DIREITO TRIBUTÁRIO`,ex:`A única grande exceção são os Embargos de Declaração, que devem ser opostos no prazo de 5 dias (Arts.`,peg:`que quase tudo é no prazo de 8 dias (Recurso Ordinário, Recurso de Revista, Agravo de Petição, Agravo de Instrumento e Embargos no TST).`},
  {num:154,disc:`Tributário`,title:`A Natureza do CTN (Lei Ordinária vs. Lei Complementar)`,kw:`CTN = STATUS DE LEI COMPLEMENTAR`,exp:`O CTN foi promulgado em 1966 como Lei Ordinária, mas, com a promulgação das Constituições de 1967 e 1988, passou a ter status de Lei Complementar. Isso ocorre porque o Art. 146, inciso III, da CF, exige que caiba à lei complementar o estabelecimento de normas gerais em matéria de legislação tributária.`,ex:`CTN pode estabelecer prescrição tributária: sim, status de LC.`,peg:`Tratar o CTN como lei ordinária.`},
  {num:155,disc:`Tributário`,title:`Tributo NÃO é multa (Conceito de Tributo)`,kw:`CONCEITO DE TRIBUTO`,exp:`O tributo é uma prestação pecuniária compulsória que expressamente não constitui sanção de ato ilícito (Art. 3º do CTN). Diferentemente da multa, que pune um comportamento infrator, o tributo pressupõe um ato lícito com natureza arrecadatória, como auferir renda ou ser proprietário de um veículo.`,ex:`Diferentemente da multa, que pune um comportamento infrator, o tributo pressupõe um ato lícito com natureza arrecadatória, como auferir renda ou ser proprietário de um veículo.`,peg:`O tributo é uma prestação pecuniária compulsória que expressamente não constitui sanção de ato ilícito (Art.`},
  {num:156,disc:`Tributário`,title:`As 5 Espécies Tributárias (Teoria Pentapartida)`,kw:`TEORIA PENTAPARTIDA`,exp:`Fique atento para a divergência na prova: embora o Art. 5º do CTN liste apenas os impostos, taxas e contribuições de melhoria, o STF e a doutrina majoritária adotam a teoria pentapartida (ou quinquipartida). Portanto, consideram-se 5 espécies: impostos, taxas, contribuições de melhoria, empréstimos compulsórios e contribuições especiais.`,ex:`Portanto, consideram-se 5 espécies: impostos, taxas, contribuições de melhoria, empréstimos compulsórios e contribuições especiais.`,peg:`para a divergência na prova: embora o Art.`},
  {num:157,disc:`Tributário`,title:`Protesto Extrajudicial e a Prescrição (NOVIDADE 2024)`,kw:`NOVIDADE 2024`,exp:`A alteração recente da Lei Complementar nº 208/2024 é quente para a prova! Agora, o protesto extrajudicial foi incluído expressamente como forma de interrupção da prescrição do crédito tributário (Art. 174, parágrafo único, do CTN). Essa inovação tem o objetivo de agilizar o processo de cobrança do Fisco e utilizar meios administrativos sem depender exclusivamente do Judiciário.`,ex:`Essa inovação tem o objetivo de agilizar o processo de cobrança do Fisco e utilizar meios administrativos sem depender exclusivamente do Judiciário.`,peg:`A alteração recente da Lei Complementar nº 208/2024 é quente para a prova.`},
  {num:158,disc:`Tributário`,title:`Interpretação Literal (A Regra das Exceções)`,kw:`A REGRA DAS EXCEÇÕES`,exp:`O Art. 111 do CTN estabelece situações estritas nas quais a interpretação da norma tributária não pode ser extensiva, devendo ser interpretada literalmente. São as regras que tratam de: suspensão ou exclusão do crédito tributário, outorga de isenção e dispensa de cumprimento de obrigações acessórias.`,ex:`São as regras que tratam de: suspensão ou exclusão do crédito tributário, outorga de isenção e dispensa de cumprimento de obrigações acessórias.`,peg:`111 do CTN estabelece situações estritas nas quais a interpretação da norma tributária não pode ser extensiva, devendo ser interpretada literalmente.`},
  {num:159,disc:`Tributário`,title:`O Princípio In Dubio Pro Contribuinte`,kw:`O PRINCÍPIO IN DUBIO PRO`,exp:`Diferente das regras que exigem interpretação literal, sempre que houver dúvida na aplicação de dispositivos que definem infrações ou cominam penalidades, a interpretação mais favorável ao contribuinte deve ser aplicada, com base no princípio da presunção de inocência (Art. 112 do CTN).`,ex:`Diferente das regras que exigem interpretação literal, sempre que houver dúvida na aplicação de dispositivos que definem infrações ou cominam penalida`,peg:`Diferente das regras que exigem interpretação literal, sempre que houver dúvida na aplicação de dispositivos que definem infrações ou cominam penalidades, a interpretação mais favorável ao contribuinte deve ser aplicada, com base no princípio da pres`},
  {num:160,disc:`Tributário`,title:`Responsabilidade Imobiliária e Arrematação em Leilão`,kw:`RESPONSABILIDADE IMOBILIÁRIA E ARREMATAÇ`,exp:`O adquirente de um imóvel responde sempre pelos débitos tributários inerentes ao bem, como o IPTU, ocorrendo a sub-rogação da dívida. A exceção de ouro que sempre cai na prova é a arrematação em hasta pública (leilão), onde o adquirente recebe o bem livre de dívidas, pois, nesse caso, a sub-rogação incide apenas sobre o preço pago pelo imóvel (Art. 130 do CTN).`,ex:`A exceção de ouro que sempre cai na prova é a arrematação em hasta pública (leilão), onde o adquirente recebe o bem livre de dívidas, pois, nesse caso, a sub-rogação incide apenas sobre o preço pago pelo imóvel (Art.`,peg:`O adquirente de um imóvel responde sempre pelos débitos tributários inerentes ao bem, como o IPTU, ocorrendo a sub-rogação da dívida.`},
  {num:161,disc:`Tributário`,title:`A Suspensão NÃO Impede o Lançamento`,kw:`A SUSPENSÃO NÃO IMPEDE O`,exp:`A suspensão da exigibilidade paralisa os atos de cobrança e execuções contra o contribuinte. Entretanto, ela não impede que o Fisco constitua o crédito por meio do lançamento. A Fazenda Pública realiza esse lançamento justamente para evitar a decadência de seu direito, já que a dívida nascerá com sua exigibilidade devidamente paralisada por decisão judicial, mas sem a aplicação de multas por atraso (Art. 151 do CTN).`,ex:`A Fazenda Pública realiza esse lançamento justamente para evitar a decadência de seu direito, já que a dívida nascerá com sua exigibilidade devidamente paralisada por decisão judicial, mas sem a aplicação de multas por atraso (Art.`,peg:`A suspensão da exigibilidade paralisa os atos de cobrança e execuções contra o contribuinte.`},
  {num:162,disc:`Tributário`,title:`A "Pegadinha" Inconstitucional do Depósito Prévio`,kw:`A "PEGADINHA" INCONSTITUCIONAL DO DEPÓSI`,exp:`É expressamente inconstitucional a exigência de depósito prévio, arrolamento de bens ou pagamento antecipado em dinheiro como requisito de admissibilidade para ajuizar ação judicial ou entrar com recurso na via administrativa (Súmulas Vinculantes 21 e 28 do STF). O depósito integral funciona apenas como uma opção/faculdade do contribuinte para suspender a cobrança.`,ex:`O depósito integral funciona apenas como uma opção/faculdade do contribuinte para suspender a cobrança.`,peg:`É expressamente inconstitucional a exigência de depósito prévio, arrolamento de bens ou pagamento antecipado em dinheiro como requisito de admissibilidade para ajuizar ação judicial ou entrar com recurso na via administrativa (Súmulas Vinculantes 21 `},
  {num:163,disc:`Tributário`,title:`Moratória Territorial/Pessoal e a Isonomia`,kw:`MORATÓRIA TERRITORIAL/PESSOAL E A ISONOM`,exp:`A concessão de moratória a uma determinada região geográfica afetada por desastres (territorial) ou restrita a uma classe em situação de vulnerabilidade (pessoal) NÃO afronta o princípio da igualdade (Art. 152, Parágrafo Único, do CTN). Pelo contrário, essa legislação diferencia os desiguais e AFIRMA o princípio da isonomia.`,ex:`Pelo contrário, essa legislação diferencia os desiguais e AFIRMA o princípio da isonomia.`,peg:`A concessão de moratória a uma determinada região geográfica afetada por desastres (territorial) ou restrita a uma classe em situação de vulnerabilidade (pessoal) NÃO afronta o princípio da igualdade (Art.`},
  {num:164,disc:`Tributário`,title:`Suspensão da Exigibilidade NÃO Dispensa Obrigação Acessória`,kw:`SUSPENSÃO DA EXIGIBILIDADE NÃO DISPENSA`,exp:`A obtenção de uma liminar ou a realização de um parcelamento suspende apenas a obrigação principal (o dever de pagar o tributo em dinheiro). No entanto, isso não dispensa o contribuinte do cumprimento das obrigações acessórias, como emitir notas fiscais, registrar transações e entregar escriturações, por serem institutos independentes e autônomos (Art. 151, Parágrafo Único, do CTN).`,ex:`151, Parágrafo Único, do CTN).`,peg:`A obtenção de uma liminar ou a realização de um parcelamento suspende apenas a obrigação principal (o dever de pagar o tributo em dinheiro).`},
  {num:165,disc:`Tributário`,title:`Restituição de Tributos Indiretos (ICMS e IPI)`,kw:`ICMS E IPI`,exp:`Na repetição de indébito de tributos que comportam repasse financeiro, a restituição só será feita a quem provar, obrigatoriamente, que assumiu o encargo (e não repassou o valor para o cliente na nota fiscal) OU, caso tenha repassado ao consumidor, que possui estar expressamente autorizado por este (o contribuinte de fato) a receber a devolução (Art. 166 do CTN e Súmula 546 do STF).`,ex:`166 do CTN e Súmula 546 do STF).`,peg:`Na repetição de indébito de tributos que comportam repasse financeiro, a restituição só será feita a quem provar, obrigatoriamente, que assumiu o encargo (e não repassou o valor para o cliente na nota fiscal) OU, caso tenha repassado ao consumidor, q`},
  {num:166,disc:`Tributário`,title:`A Vedação à Compensação Baseada em Liminar`,kw:`A VEDAÇÃO À COMPENSAÇÃO BASEADA`,exp:`A compensação ocorre quando as partes são credoras e devedoras entre si e abatem a dívida. Mas, cuidado: é terminantemente vedada a compensação de débitos tributários mediante o aproveitamento de créditos que ainda são objeto de contestação judicial sem decisão definitiva (Art. 170-A do CTN). Ou seja, não é permitido compensar crédito tributário com base apenas em provimento liminar ou tutela antecipada antes do trânsito em julgado da decisão. DIREITO EMPRESARIAL`,ex:`Ou seja, não é permitido compensar crédito tributário com base apenas em provimento liminar ou tutela antecipada antes do trânsito em julgado da decisão.`,peg:`é terminantemente vedada a compensação de débitos tributários mediante o aproveitamento de créditos que ainda são objeto de contestação judicial sem decisão definitiva (Art.`},
  {num:167,disc:`Empresarial`,title:`A Exceção dos Profissionais Intelectuais`,kw:`A EXCEÇÃO DOS PROFISSIONAIS INTELECTUAIS`,exp:`A regra é que profissionais que exercem atividade intelectual (médicos, advogados, dentistas, artistas) não são considerados empresários, mesmo que contratem auxiliares. A exceção para a prova é: se o exercício da profissão constituir "elemento de empresa" (ou seja, a organização dos fatores de produção for mais importante que a atividade intelectual em si), ele será enquadrado como empresário (Art. 966, Parágrafo único, do Código Civil).`,ex:`966, Parágrafo único, do Código Civil).`,peg:`A regra é que profissionais que exercem atividade intelectual (médicos, advogados, dentistas, artistas) não são considerados empresários, mesmo que contratem auxiliares.`},
  {num:168,disc:`Empresarial`,title:`A Pegadinha do Registro (Comum x Rural)`,kw:`COMUM X RURAL`,exp:`Para o empresário comum, a inscrição na Junta Comercial é obrigatória antes de iniciar as atividades, mas seu registro tem natureza apenas declaratória; ele já adquire o status de empresário pela simples prática da atividade. Já para o empresário rural, a inscrição é facultativa, e seu registro tem natureza constitutiva, ou seja, ele só se equipara a empresário e ganha os direitos empresariais (como pedir recuperação judicial) após a inscrição (Art. 967 e Art. 971 do Código Civil).`,ex:`Já para o empresário rural, a inscrição é facultativa, e seu registro tem natureza constitutiva, ou seja, ele só se equipara a empresário e ganha os direitos empresariais (como pedir recuperação judicial) após a inscrição (Art.`,peg:`Para o empresário comum, a inscrição na Junta Comercial é obrigatória antes de iniciar as atividades, mas seu registro tem natureza apenas declaratória; ele já adquire o status de empresário pela simples prática da atividade.`},
  {num:169,disc:`Empresarial`,title:`Venda de Imóveis da Empresa e o Casamento`,kw:`VENDA DE IMÓVEIS DA EMPRESA`,exp:`Este é um ponto de alta incidência nas provas. O empresário casado NÃO precisa da autorização do cônjuge (outorga conjugal) para alienar ou gravar com ônus real os imóveis que integrem o patrimônio da empresa, independentemente do regime de bens do casamento (Art. 978 do Código Civil).`,ex:`O empresário casado NÃO precisa da autorização do cônjuge (outorga conjugal) para alienar ou gravar com ônus real os imóveis que integrem o patrimônio da empresa, independentemente do regime de bens do casamento (Art.`,peg:`Este é um ponto de alta incidência nas provas.`},
  {num:170,disc:`Empresarial`,title:`O Incapaz NUNCA inicia empresa`,kw:`O INCAPAZ NUNCA INICIA EMPRESA`,exp:`A regra é clara: o incapaz não pode iniciar uma atividade empresarial. Contudo, ele pode continuar uma empresa que já exercia enquanto era capaz, ou que herdou de seus pais, desde que possua autorização judicial prévia. Nesse caso, o macete de proteção patrimonial é que os bens pessoais que o incapaz já possuía não responderão pelas dívidas do negócio (Art. 974, § 1º e 2º, do Código Civil).`,ex:`974, § 1º e 2º, do Código Civil).`,peg:`A regra é clara: o incapaz não pode iniciar uma atividade empresarial.`},
  {num:171,disc:`Empresarial`,title:`A Solidariedade Oculta na LTDA e a Vedação de Serviços`,kw:`A SOLIDARIEDADE OCULTA NA LTDA`,exp:`Na Sociedade Limitada, a responsabilidade do sócio é restrita ao valor de suas quotas. Porém, todos os sócios respondem solidariamente pela integralização do capital social. Ou seja, se um sócio não pagou sua parte, os credores podem cobrar a diferença de qualquer outro sócio. Além disso, diferentemente da sociedade simples, na LTDA é expressamente vedada a contribuição ao capital que consista em prestação de serviços (Art. 1052 e Art. 1055 do Código Civil).`,ex:`Além disso, diferentemente da sociedade simples, na LTDA é expressamente vedada a contribuição ao capital que consista em prestação de serviços (Art.`,peg:`Na Sociedade Limitada, a responsabilidade do sócio é restrita ao valor de suas quotas.`},
  {num:172,disc:`Empresarial`,title:`Títulos de Crédito`,kw:`TÍTULOS DE CRÉDITO`,exp:`Quem precisa de Aceite? Na hora da prova, lembre-se das diferenças na formação da obrigação. Letra de Câmbio e Duplicata são ordens de pagamento e precisam do "Aceite" (ato em que o sacado concorda em pagar) para vincular o devedor principal. Já o Cheque e a Nota Promissória NÃO têm aceite, pois a obrigação do devedor principal já nasce assim que ele assina a emissão do título.`,ex:`Já o Cheque e a Nota Promissória NÃO têm aceite, pois a obrigação do devedor principal já nasce assim que ele assina a emissão do título.`,peg:`das diferenças na formação da obrigação.`},
  {num:173,disc:`Empresarial`,title:`Aval Parcial (O Conflito de Leis)`,kw:`O CONFLITO DE LEIS`,exp:`Se a OAB cobrar se é válido dar um aval garantindo apenas parte da dívida, responda dependendo da lei. O Código Civil proíbe o aval parcial (Art. 897), aplicando-se aos títulos atípicos. Porém, como a lei especial prevalece sobre a geral, a Lei Uniforme de Genebra (LUG) permite o aval parcial, sendo totalmente válido para a Letra de Câmbio e a Nota Promissória.`,ex:`Porém, como a lei especial prevalece sobre a geral, a Lei Uniforme de Genebra (LUG) permite o aval parcial, sendo totalmente válido para a Letra de Câmbio e a Nota Promissória.`,peg:`Se a OAB cobrar se é válido dar um aval garantindo apenas parte da dívida, responda dependendo da lei.`},
  {num:174,disc:`Empresarial`,title:`O Stay Period e as suas Exceções`,kw:`O STAY PERIOD E AS`,exp:`Ao deferir o processamento da Recuperação Judicial, inicia-se o stay period de 180 dias (prorrogável uma vez), suspendendo todas as execuções contra o devedor (Art. 6º, § 4º, da Lei 11.101/05). O macete é decorar o que NÃO é suspenso: execuções fiscais, créditos extraconcursais (ex: credor fiduciário), e ações que demandam quantia ilíquida ou trabalhistas (que prosseguem no juízo de origem até o valor ser apurado).`,ex:`O macete é decorar o que NÃO é suspenso: execuções fiscais, créditos extraconcursais (ex: credor fiduciário), e ações que demandam quantia ilíquida ou trabalhistas (que prosseguem no juízo de origem até o valor ser apurado).`,peg:`Ao deferir o processamento da Recuperação Judicial, inicia-se o stay period de 180 dias (prorrogável uma vez), suspendendo todas as execuções contra o devedor (Art.`},
  {num:175,disc:`Empresarial`,title:`A Punição da Habilitação Retardatária`,kw:`A PUNIÇÃO DA HABILITAÇÃO RETARDATÁRIA`,exp:`O credor tem 15 dias após o edital para habilitar seu crédito administrativamente. Se perder esse prazo, seu crédito será recebido como retardatário. A grande consequência/punição para a prova é que, na Recuperação Judicial, o credor retardatário perde o direito de voto na Assembleia-Geral de Credores (AGC). A única exceção legal são os créditos trabalhistas retardatários, que mantêm o seu direito de voto intacto (Art. 10 da Lei 11.101/05).`,ex:`A única exceção legal são os créditos trabalhistas retardatários, que mantêm o seu direito de voto intacto (Art.`,peg:`O credor tem 15 dias após o edital para habilitar seu crédito administrativamente.`},
  {num:176,disc:`Empresarial`,title:`A Regra dos 150 Salários-Mínimos na Falência`,kw:`A REGRA DOS 150 SALÁRIOS-MÍNIMOS`,exp:`Na falência, após o pagamento dos credores extraconcursais, pagam-se os credores concursais. Os primeiros dessa fila são os créditos trabalhistas (e acidentes de trabalho). Mas cuidado com o teto absoluto: essa preferência é limitada a 150 salários-mínimos por credor. O valor do saldo trabalhista que ultrapassar esse limite cai para o final da fila e será pago como crédito quirografário (Art. 83 da Lei 11.101/05). DIREITOS HUMANOS`,ex:`O valor do saldo trabalhista que ultrapassar esse limite cai para o final da fila e será pago como crédito quirografário (Art.`,peg:`com o teto absoluto: essa preferência é limitada a 150 salários-mínimos por credor.`},
  {num:177,disc:`Direitos Humanos`,title:`A Hierarquia "Dupla" dos Tratados de Direitos Humanos`,kw:`3/5 DOIS TURNOS=EMENDA / DEMAIS=SUPRALEG`,exp:`Os tratados internacionais de direitos humanos podem ocupar duas posições distintas no ordenamento jurídico brasileiro. Se forem aprovados em cada Casa do Congresso Nacional (Câmara e Senado), em dois turnos, por 3/5 dos votos, terão status equivalente ao de Emenda Constitucional (Art. 5º, § 3º, da CF/88). Contudo, se o tratado não for aprovado por esse quórum especial (ou for anterior à EC 45/2004, como o Pacto de San José da Costa Rica), ele terá status supralegal: fica abaixo da Constituiç...`,ex:`Pacto de San José da Costa Rica: status supralegal.`,peg:`Tratar todos os tratados de DH como emenda constitucional.`},
  {num:178,disc:`Direitos Humanos`,title:`A Pegadinha da Pena de Morte no Pacto de San José`,kw:`A PEGADINHA DA PENA DE`,exp:`O Direito à Vida é protegido desde a concepção pelo Artigo 4º do Pacto de São José da Costa Rica, mas a Convenção permite a aplicação da pena de morte em circunstâncias limitadas. O macete para gabaritar na OAB é focar nas proibições absolutas deste artigo: se um país aboliu a pena de morte, é terminantemente proibido reinstaurá-la. Além disso, a pena capital jamais poderá ser aplicada por delitos políticos ou conexos, e não pode ser imposta a menores de 18 anos, a maiores de 70 anos, nem a m...`,ex:`Além disso, a pena capital jamais poderá ser aplicada por delitos políticos ou conexos, e não pode ser imposta a menores de 18 anos, a maiores de 70 anos, nem a mulheres grávidas.`,peg:`gabaritar na OAB é focar nas proibições absolutas deste artigo: se um país aboliu a pena de morte, é terminantemente proibido reinstaurá-la.`},
  {num:179,disc:`Direitos Humanos`,title:`Acesso ao Sistema Interamericano (Comissão x Corte)`,kw:`COMISSÃO X CORTE`,exp:`As bancas adoram inverter as competências desses dois órgãos. Para não errar, lembre-se das portas de entrada: a Comissão Interamericana atua como um órgão administrativo, de mediação e monitoramento, e pode receber denúncias de qualquer pessoa, grupo de pessoas ou entidade. Por outro lado, a Corte Interamericana é um tribunal de caráter jurisdicional com decisões definitivas e inapeláveis, mas o indivíduo comum não tem acesso direto a ela: apenas os Estados e a própria Comissão possuem compe...`,ex:`DIREITO AMBIENTAL 3 Macetes para Gabaritar Direito Ambiental na OAB.`,peg:`das portas de entrada: a Comissão Interamericana atua como um órgão administrativo, de mediação e monitoramento, e pode receber denúncias de qualquer pessoa, grupo de pessoas ou entidade.`},
  {num:180,disc:`Ambiental`,title:`Prevenção vs. Precaução (O Macete do Risco)`,kw:`O MACETE DO RISCO`,exp:`As bancas adoram tentar confundir esses dois princípios, mas a diferença está no nível de conhecimento sobre o perigo. Aplica-se o Princípio da Prevenção quando o risco de dano ambiental é certo, conhecido e previsível. Por outro lado, aciona-se o Princípio da Precaução quando os riscos da atividade são incertos, desconhecidos e imprevisíveis.`,ex:`Por outro lado, aciona-se o Princípio da Precaução quando os riscos da atividade são incertos, desconhecidos e imprevisíveis.`,peg:`As bancas adoram tentar confundir esses dois princípios, mas a diferença está no nível de conhecimento sobre o perigo.`},
  {num:181,disc:`Ambiental`,title:`Cômputo da APP na Reserva Legal`,kw:`CÔMPUTO DA APP NA RESERVA`,exp:`Diferente do que muitos pensam, é perfeitamente possível que a Área de Preservação Permanente (APP) seja contabilizada dentro do percentual exigido para a Reserva Legal (RL) da propriedade rural, reduzindo a área total restrita. O Código Florestal (Lei 12.651/2012) autoriza esse cômputo desde que preenchidos três requisitos cumulativos: a APP deve estar conservada ou em processo de recuperação, o proprietário deve ter solicitado a inclusão do imóvel no Cadastro Ambiental Rural (CAR) e a soma ...`,ex:`651/2012) autoriza esse cômputo desde que preenchidos três requisitos cumulativos: a APP deve estar conservada ou em processo de recuperação, o proprietário deve ter solicitado a inclusão do imóvel no Cadastro Ambiental Rural (CAR) e a soma não pode `,peg:`Diferente do que muitos pensam, é perfeitamente possível que a Área de Preservação Permanente (APP) seja contabilizada dentro do percentual exigido para a Reserva Legal (RL) da propriedade rural, reduzindo a área total restrita.`},
  {num:182,disc:`Ambiental`,title:`A Omissão do Estado e a Execução Subsidiária`,kw:`A OMISSÃO DO ESTADO E`,exp:`A regra geral da responsabilidade civil ambiental é de que ela é objetiva e solidária entre todos os causadores. Contudo, o grande macete de prova envolve a atuação do poder público: quando o Estado é responsabilizado por omissão no dever de fiscalizar, ele atua apenas como um "devedor reserva". Segundo a Súmula 652 do STJ, o Estado responde objetiva e solidariamente, mas a sua execução será subsidiária. Isso significa que o credor deve primeiro tentar cobrar do causador direto do dano e, ape...`,ex:`Isso significa que o credor deve primeiro tentar cobrar do causador direto do dano e, apenas se este não for encontrado ou não puder pagar, o Estado será acionado para arcar com a reparação.`,peg:`A regra geral da responsabilidade civil ambiental é de que ela é objetiva e solidária entre todos os causadores.`},
  {num:183,disc:`ECA`,title:`Adoção (A Regra Numérica dos 18 e 16 anos)`,kw:`A REGRA NUMÉRICA DOS 18 E 16 ANOS`,exp:`A adoção é um tema que despenca na prova e é uma medida excepcional e irrevogável. Para adotar, o indivíduo deve ser maior de 18 anos, independentemente do estado civil. O grande macete numérico que a FGV adora cobrar é a diferença de idade obrigatória: o adotante deve ser, no mínimo, 16 anos mais velho que o adotando. Além disso, se o adotando for maior de 12 anos, o seu consentimento é obrigatório. (Arts. 39, 42, caput e § 3º, e 45, § 2º do ECA).`,ex:`39, 42, caput e § 3º, e 45, § 2º do ECA).`,peg:`A adoção é um tema que despenca na prova e é uma medida excepcional e irrevogável.`},
  {num:184,disc:`ECA`,title:`Autorização para Viagem Nacional (O Limite dos 16 Anos)`,kw:`O LIMITE DOS 16 ANOS`,exp:`Esse é considerado um ponto de alta incidência. A regra geral determina que menores de 16 anos desacompanhados precisam de autorização judicial para viajar fora de sua comarca. A pegadinha está nas exceções em que a autorização judicial não é exigida: 1) Viagem para comarca vizinha (contígua) ou mesma região metropolitana; 2) Se estiver acompanhado de avós/bisavós (ascendentes) ou tios/irmãos maiores de idade (colaterais até o 3º grau), comprovando documentalmente o parentesco. O macete de ou...`,ex:`O macete de ouro: para o adolescente maior de 16 anos, nenhuma viagem nacional exige autorização judicial.`,peg:`Esse é considerado um ponto de alta incidência.`},
  {num:185,disc:`ECA`,title:`A Excepcionalidade até os 21 Anos (Súmula 605 STJ)`,kw:`SÚMULA 605 STJ`,exp:`Adolescentes são inimputáveis penalmente e sujeitos a medidas socioeducativas se praticarem ato infracional (fato análogo a crime) entre 12 e 18 anos. Mas o que acontece se ele completar 18 anos durante o processo ou cumprimento da medida? O STF e o STJ já pacificaram: a superveniência da maioridade penal não interfere na apuração do ato infracional ou na execução da medida em curso. O Estado pode continuar aplicando as medidas socioeducativas do ECA até o jovem completar, no limite máximo, 2...`,ex:`121, § 5º do ECA e Súmula 605 do STJ).`,peg:`Adolescentes são inimputáveis penalmente e sujeitos a medidas socioeducativas se praticarem ato infracional (fato análogo a crime) entre 12 e 18 anos.`},
  {num:186,disc:`Consumidor`,title:`A Diferença de Ouro`,kw:`A DIFERENÇA DE OURO`,exp:`Vício x Fato do Produto (Prazos): A banca adora confundir esses dois conceitos e os seus prazos. Lembre-se desta regra: • Vício: É um problema de adequação (o produto não funciona direito). O dano é intrínseco (atinge o próprio produto). Nesse caso, aplica-se o prazo decadencial (fique atento a palavras como "caduca" ou prazo para "reclamar" na prova). (Arts. 18 a 20 e 26 do CDC). • Fato (Defeito): É um problema de segurança (acidente de consumo). O dano é extrínseco, atingindo a integridade ...`,ex:`Nesse caso, a responsabilidade é independente de culpa e o prazo é prescricional de 5 anos para a pretensão de reparação.`,peg:`a palavras como "caduca" ou prazo para "reclamar" na prova).`},
  {num:187,disc:`Consumidor`,title:`O Limite do Direito de Arrependimento`,kw:`O LIMITE DO DIREITO DE`,exp:`O direito de arrependimento (ou prazo de reflexão) garante que o consumidor desista da compra no prazo de 7 dias, recebendo os valores de volta imediatamente e atualizados. O macete crucial para não cair em pegadinha é: esse direito se aplica exclusivamente às contratações realizadas fora do estabelecimento comercial (ex: telefone, compras a domicílio ou pela internet). Se a compra foi feita presencialmente dentro da loja física, o CDC não garante o direito de arrependimento por simples desis...`,ex:`Se a compra foi feita presencialmente dentro da loja física, o CDC não garante o direito de arrependimento por simples desistência.`,peg:`O direito de arrependimento (ou prazo de reflexão) garante que o consumidor desista da compra no prazo de 7 dias, recebendo os valores de volta imediatamente e atualizados.`},
  {num:188,disc:`Consumidor`,title:`As Pegadinhas do STJ sobre Dano Moral e Práticas Abusivas`,kw:`AS PEGADINHAS DO STJ SOBRE`,exp:`O STJ possui entendimentos sumulados que são cobrados frequentemente. Memorize estes dois cenários clássicos: • Cartão de Crédito: O simples envio de um cartão de crédito sem prévia e expressa solicitação do consumidor é considerado prática comercial abusiva, configurando ato ilícito indenizável (dano moral) e sujeito a multa administrativa. (Súmula 532 do STJ). • Anotação Irregular (A Exceção): Se o consumidor tiver o nome negativado de forma irregular (indevida), a regra é que gera dano mor...`,ex:`Contudo, se ele já possuir uma inscrição legítima preexistente no cadastro de proteção ao crédito, a regra muda: não caberá indenização por dano moral, ficando ressalvado apenas o seu direito de pedir o cancelamento da anotação irregular.`,peg:`O STJ possui entendimentos sumulados que são cobrados frequentemente.`},
  {num:189,disc:`Internacional`,title:`A Exceção do Divórcio Consensual Estrangeiro`,kw:`A EXCEÇÃO DO DIVÓRCIO CONSENSUAL`,exp:`A regra geral de Direito Internacional é que qualquer sentença judicial proferida no exterior precisa passar pelo juízo de delibação e ser homologada pelo Superior Tribunal de Justiça (STJ) para ter eficácia no Brasil. O grande macete de prova, previsto no Código de Processo Civil, é a sua exceção: a sentença estrangeira de divórcio consensual produz efeitos no Brasil independentemente de homologação pelo STJ.`,ex:`O grande macete de prova, previsto no Código de Processo Civil, é a sua exceção: a sentença estrangeira de divórcio consensual produz efeitos no Brasil independentemente de homologação pelo STJ.`,peg:`A regra geral de Direito Internacional é que qualquer sentença judicial proferida no exterior precisa passar pelo juízo de delibação e ser homologada pelo Superior Tribunal de Justiça (STJ) para ter eficácia no Brasil.`},
  {num:190,disc:`Internacional`,title:`LINDB e a Regra do Domicílio x Bens x Sucessão`,kw:`LINDB E A REGRA DO`,exp:`A FGV adora tentar confundir os elementos de conexão da Lei de Introdução às Normas do Direito Brasileiro (LINDB). Memorize esta tríade infalível: 1. Para decidir sobre começo/fim da personalidade, nome, capacidade e direitos de família, aplica-se a lei do domicílio da pessoa (Art. 7º da LINDB). 2. Para qualificar e reger as relações sobre bens, aplica-se a lei do país onde os bens estão situados (Princípio da lex rei sitae, Art. 8º da LINDB). 3. Para a sucessão (herança), a regra é a lei do ...`,ex:`Para a sucessão (herança), a regra é a lei do domicílio do falecido, independentemente da natureza e da situação em que os bens se encontrem (Art.`,peg:`A FGV adora tentar confundir os elementos de conexão da Lei de Introdução às Normas do Direito Brasileiro (LINDB).`},
  {num:191,disc:`Internacional`,title:`Vedações à Extradição (A Regra dos 2 anos e Crimes Políticos)`,kw:`A REGRA DOS 2 ANOS E CRIMES POLÍTICOS`,exp:`A Lei de Migração (Lei 13.445/2017) traz hipóteses em que a extradição jamais será concedida pelo Brasil. Além da vedação absoluta de extraditar o brasileiro nato, não se concederá a extradição se a pena aplicável ao crime for inferior a 2 anos. Também é vedada a extradição se o indivíduo for beneficiário de refúgio ou asilo territorial, ou se o fato constituir crime político ou de opinião (ressalvada a exceção para crimes contra a humanidade ou crimes comuns conexos). FILOSOFIA`,ex:`Também é vedada a extradição se o indivíduo for beneficiário de refúgio ou asilo territorial, ou se o fato constituir crime político ou de opinião (ressalvada a exceção para crimes contra a humanidade ou crimes comuns conexos).`,peg:`445/2017) traz hipóteses em que a extradição jamais será concedida pelo Brasil.`},
  {num:192,disc:`Filosofia`,title:`Aristóteles`,kw:`ARISTÓTELES`,exp:`Justiça Distributiva e a "Régua" da Equidade: Na teoria de Aristóteles, a Justiça Distributiva rege a relação do Estado com os cidadãos baseada na proporcionalidade (tratar os desiguais de forma desigual na medida exata de suas desigualdades). O grande macete para a prova é associar esse conceito ao princípio da capacidade contributiva no Direito Tributário (quem tem mais, paga mais). Além disso, quando a "letra fria da lei" for rígida demais para um caso concreto, Aristóteles invoca a Equida...`,ex:`140 do Código de Processo Civil (CPC), que determina que o juiz só decidirá por equidade nos casos previstos em lei.`,peg:`Justiça Distributiva e a "Régua" da Equidade: Na teoria de Aristóteles, a Justiça Distributiva rege a relação do Estado com os cidadãos baseada na proporcionalidade (tratar os desiguais de forma desigual na medida exata de suas desigualdades).`},
  {num:193,disc:`Filosofia`,title:`Norberto Bobbio e a Solução de Antinomias (O "Super Trunfo" Hierárquico)`,kw:`O "SUPER TRUNFO" HIERÁRQUICO`,exp:`Para Bobbio, o ordenamento jurídico precisa ser coerente. Quando duas normas entram em choque (antinomia), usamos 3 critérios de solução: Hierárquico, Cronológico e da Especialidade. A pegadinha clássica da OAB é perguntar o que acontece se os critérios entrarem em conflito entre si (ex: uma lei constitucional antiga e genérica contra uma lei ordinária nova e específica). O macete é: o Critério Hierárquico sempre vence! Ele atua como um "Super Trunfo", fazendo a norma superior prevalecer em q...`,ex:`59 da CF/88) que invalida leis ordinárias conflitantes.`,peg:`o Critério Hierárquico sempre vence! Ele atua como um "Super Trunfo", fazendo a norma superior prevalecer em qualquer cenário.`},
  {num:194,disc:`Financeiro`,title:`Princípio da Exclusividade na LOA (A Regra e a Exceção)`,kw:`A REGRA E A EXCEÇÃO`,exp:`A Lei Orçamentária Anual (LOA) não pode ser usada como um "trem pagador" para aprovar matérias alheias ao orçamento, ou seja, não pode conter dispositivo estranho à previsão de receita e à fixação de despesa. Contudo, as bancas adoram cobrar as duas únicas exceções permitidas que podem constar no texto da LOA: a autorização para abertura de créditos suplementares e a autorização para a contratação de operações de crédito (empréstimos), inclusive por antecipação de receita. (Art. 165, § 8º, da...`,ex:`165, § 8º, da Constituição Federal).`,peg:`A Lei Orçamentária Anual (LOA) não pode ser usada como um "trem pagador" para aprovar matérias alheias ao orçamento, ou seja, não pode conter dispositivo estranho à previsão de receita e à fixação de despesa.`},
  {num:195,disc:`Financeiro`,title:`Cessão Onerosa da Dívida Ativa (Novidade Legislativa de 2024!)`,kw:`NOVIDADE LEGISLATIVA DE 2024!`,exp:`Preste muita atenção na inclusão recente feita pela LC 208/2024, pois tem altíssima chance de cair na prova! A União, Estados, DF e Municípios agora podem ceder (vender) onerosamente seus direitos creditórios de tributos e dívida ativa para a iniciativa privada. O macete para gabaritar é decorar dois detalhes da operação: primeiro, a cessão deve ser de caráter definitivo, de modo que o ente público (cedente) fica isento de qualquer responsabilidade pelo pagamento se o contribuinte não pagar a...`,ex:`O macete para gabaritar é decorar dois detalhes da operação: primeiro, a cessão deve ser de caráter definitivo, de modo que o ente público (cedente) fica isento de qualquer responsabilidade pelo pagamento se o contribuinte não pagar a dívida ao cessi`,peg:`Preste muita atenção na inclusão recente feita pela LC 208/2024, pois tem altíssima chance de cair na prova.`},
  {num:196,disc:`Eleitoral`,title:`Inelegibilidade Reflexa (A Exceção do Parentesco)`,kw:`A EXCEÇÃO DO PARENTESCO`,exp:`Cônjuges e parentes consanguíneos ou afins, até o segundo grau ou por adoção, do Presidente da República, de Governador ou de Prefeito (ou de quem os substituiu nos 6 meses antes do pleito) são inelegíveis no território de jurisdição do titular. O grande macete (e pegadinha clássica da FGV) é a exceção: essa regra de inelegibilidade não se aplica se o parente já for titular de mandato eletivo e candidato à reeleição. Exemplo prático: a esposa de um Governador não pode se candidatar ao cargo d...`,ex:`Exemplo prático: a esposa de um Governador não pode se candidatar ao cargo de Deputada Estadual naquele estado pela primeira vez, mas, se ela já for Deputada Estadual, sua candidatura à reeleição é perfeitamente permitida (Art.`,peg:`Cônjuges e parentes consanguíneos ou afins, até o segundo grau ou por adoção, do Presidente da República, de Governador ou de Prefeito (ou de quem os substituiu nos 6 meses antes do pleito) são inelegíveis no território de jurisdição do titular.`},
  {num:197,disc:`Eleitoral`,title:`Coligações vs. Federações Partidárias (O Macete do Tempo e do Cargo)`,kw:`O MACETE DO TEMPO E DO CARGO`,exp:`É crucial não confundir essas duas formas de união de partidos, pois as diferenças despencam nas provas. As Coligações possuem vínculo temporário (existem apenas durante o processo eleitoral) e são permitidas exclusivamente para eleições majoritárias (Presidente, Governador, Prefeito e Senador). Por outro lado, as Federações possuem um vínculo estável e duradouro (com permanência mínima exigida de 4 anos) e atuam em todas as eleições (majoritárias e proporcionais), funcionando administrativa ...`,ex:`Vale lembrar que a própria Constituição proíbe expressamente a celebração de coligações em eleições proporcionais (Art.`,peg:`É crucial não confundir essas duas formas de união de partidos, pois as diferenças despencam nas provas.`},
  {num:198,disc:`Previdenciário`,title:`A Pegadinha da Carência no Salário-Maternidade`,kw:`A PEGADINHA DA CARÊNCIA NO`,exp:`A regra geral prevê que o salário-maternidade exige uma carência de 10 contribuições mensais para as seguradas contribuinte individual, especial e facultativa. O grande macete de prova é a exceção: a exigência de carência é totalmente dispensada para as categorias que possuem vínculo de emprego ou equiparado, ou seja, a Segurada Empregada, a Trabalhadora Avulsa e a Empregada Doméstica. (Art. 26 da Lei 8.213/91).`,ex:`O grande macete de prova é a exceção: a exigência de carência é totalmente dispensada para as categorias que possuem vínculo de emprego ou equiparado, ou seja, a Segurada Empregada, a Trabalhadora Avulsa e a Empregada Doméstica.`,peg:`A regra geral prevê que o salário-maternidade exige uma carência de 10 contribuições mensais para as seguradas contribuinte individual, especial e facultativa.`},
  {num:199,disc:`Previdenciário`,title:`O Adicional de 25% "Fura-Teto"`,kw:`25% MESMO ACIMA DO TETO RGPS`,exp:`Na Aposentadoria por Invalidez, se o segurado necessitar de assistência permanente de outra pessoa, ele terá direito a um acréscimo de 25% no valor do seu benefício. A FGV adora testar o limite desse valor, então memorize: este adicional de 25% deve ser pago mesmo que o valor total da aposentadoria ultrapasse o teto máximo de pagamento do Regime Geral de Previdência Social (RGPS). (Art. 45 da Lei 8.213/91).`,ex:`Aposentado no teto: 25% pago acima do teto.`,peg:`Limitar o adicional de 25% ao teto do RGPS.`},
]

